const questionsFr: Question[] = [
  // Définition du triton
  { q: "Un triton est un intervalle de...", opts: ["5 demi-tons", "6 demi-tons", "7 demi-tons", "4 demi-tons"], a: 1, fb: "Le triton = 6 demi-tons = quarte augmentée = quinte diminuée. C'est l'intervalle le plus dissonant de la gamme tempérée — il divise l'octave (12 demi-tons) exactement en deux. Ex : Do → Fa# = 6 demi-tons." },
  { q: "Pourquoi appelle-t-on le triton 'diabolus in musica' au Moyen Âge ?", opts: ["C'était facile à jouer", "C'était l'intervalle le plus consonant", "Sa dissonance extrême était considérée dangereuse et était proscrite", "Il ressemblait au son d'un diable"], a: 2, fb: "Au Moyen Âge et à la Renaissance, le triton était explicitement interdit dans la musique d'église en raison de sa dissonance. 'Diabolus in musica' (diable dans la musique) est une expression qui date du traité de Johannes de Muris (XIVe siècle)." },
  { q: "Le triton de Sol est...", opts: ["Ré", "Do#", "Réb", "La"], a: 2, fb: "Sol → Réb = 6 demi-tons (Sol=7, Sol#=8, La=9, Sib=10, Si=11, Do=12, Réb=13... en partant de Do=0 : Sol=7, +6=13=Réb à l'octave sup... plutôt : G=7, +6=13=Db modulaire). Sol + 6 = Réb. C'est pourquoi Db7 est la substitution tritonique de G7." },
  { q: "Le triton de Do est...", opts: ["Sol", "Fa#", "Sib", "La#"], a: 1, fb: "Do → Fa# = 6 demi-tons. Do=0, +6=Fa#(Gb). La substitution tritonique de C7 est F#7 (ou Gb7 selon le contexte)." },
  { q: "Le triton de Ré est...", opts: ["Sol#", "Lab", "Sol#/Lab (enharmoniques)", "Sol"], a: 2, fb: "Ré + 6 demi-tons = Sol# = Lab (notes enharmoniques). Les deux notations sont équivalentes. La substitution tritonique de D7 est Ab7." },
  { q: "Combien de paires de substitutions tritoniques existent dans les 12 tonalités ?", opts: ["6 paires", "12 paires", "24 paires", "3 paires"], a: 0, fb: "Il y a 6 paires de substitutions tritoniques : G7↔Db7, D7↔Ab7, A7↔Eb7, E7↔Bb7, B7↔F7, F#7↔C7. Chaque paire partage le même triton interne (les guide tones)." },
  // Le triton partagé
  { q: "G7 contient le triton B – F. Dans Db7, ces mêmes notes sont...", opts: ["La 9te et la 5te", "La ♭7te (Cb=B) et la 3ce (F)", "La 3ce et la quinte", "La fondamentale et la 9te"], a: 1, fb: "Dans Db7 : la 3ce est Fa (F) et la ♭7te est Do♭ (Cb = B naturel enharmoniquement). Le triton F–B est partagé entre G7 et Db7, mais les rôles s'inversent : B (3ce de G7) devient ♭7 de Db7 ; F (♭7 de G7) devient 3ce de Db7." },
  { q: "Les 'guide tones' d'un accord sont...", opts: ["la fondamentale et la 5te", "la 3ce et la 7te", "la 9te et la 13te", "la fondamentale et la 9te"], a: 1, fb: "Les guide tones = 3ce + 7te. Ce sont les notes qui définissent la qualité (majeur/mineur) et la tension (dominant/Maj7) d'un accord. La fondamentale et la 5te sont acoustiquement redondantes ; 3ce et 7te portent toute l'information harmonique." },
  { q: "Dans la substitution tritonique, les guide tones...", opts: ["disparaissent complètement", "restent identiques mais échangent leurs rôles (3ce ↔ 7te)", "se déplacent d'un demi-ton", "doublent d'octave"], a: 1, fb: "C'est le secret de la substitution tritonique : les deux notes du triton restent présentes, mais leurs rôles s'inversent. La 3ce de G7 (Si/B) devient la ♭7te de Db7 (Do♭/Cb). La ♭7te de G7 (Fa/F) devient la 3ce de Db7 (Fa/F). Les deux accords résolvent vers C pour la même raison : ils partagent le même triton instable." },
  { q: "Pourquoi G7 et Db7 résolvent-ils tous deux vers C majeur ?", opts: ["Par convention historique uniquement", "Car ils partagent le même triton interne (B–F = Cb–F) qui résout vers C", "Car ils ont la même fondamentale", "Car ils ont la même 5te"], a: 1, fb: "G7 et Db7 partagent les notes B (=Cb) et F — le triton. Ce triton se résout vers C et E (B→C demi-ton ascendant, F→E demi-ton descendant). Peu importe que la basse soit G ou Db, les guide tones résolvent identiquement vers CMaj7." },
  { q: "La résolution du triton B–F vers C–E implique...", opts: ["B monte d'un demi-ton vers C ; F descend d'un demi-ton vers E", "B descend vers A ; F monte vers G", "B et F restent en place", "B monte d'un ton vers C# ; F descend d'un ton vers Eb"], a: 0, fb: "B → C (demi-ton ascendant) et F → E (demi-ton descendant). Ces deux mouvements de demi-ton convergent vers la tonique C et sa 3ce E. C'est cette attraction du triton vers la tierce majeure de la tonique qui génère la tension → résolution." },
  // La ligne de basse
  { q: "La cadence standard G7 → C implique quel mouvement de basse ?", opts: ["Chromatique descendant (G→Gb→F→E→...→C)", "Descente de quinte (G down to C = descente de quinte juste)", "Montée de quarte", "Reste sur G"], a: 1, fb: "G7 → C : la basse descend d'une quinte juste (7 demi-tons) de Sol à Do. Ce mouvement de quinte descendante (ou montée de quarte) est le mouvement cadentiel le plus fort de la tonalité — la raison pour laquelle V→I est la résolution archétypale." },
  { q: "La cadence tritonique Db7 → C implique quel mouvement de basse ?", opts: ["Descente de quinte (Db → Gb)", "Montée d'un demi-ton (Db→D)", "Descente d'un demi-ton chromatique (Db→C)", "Reste sur Db"], a: 2, fb: "Db7 → C : la basse descend d'un demi-ton de Réb à Do. C'est le mouvement chromatique le plus lisse possible. Cette résolution par glissement (plutôt que par saut de quinte) est l'avantage principal de la substitution tritonique : douceur et chromatisme." },
  { q: "Dans le II-V-I standard (Dm7–G7–CMaj7), la ligne de basse est...", opts: ["D → Db → C (chromatique)", "D → G → C (5tes descendantes)", "D → E → C", "D → A → C"], a: 1, fb: "Dm7–G7–CMaj7 en Do : basse = Ré–Sol–Do. Ré→Sol = quinte descendante (ou quarte montante) ; Sol→Do = quinte descendante. Progression par cycle des quintes — très fort harmoniquement, moins lisse linéairement." },
  { q: "Dans le II-V-I avec substitution (Dm7–Db7–CMaj7), la ligne de basse est...", opts: ["D → G → C", "D → Db → C (descente chromatique !)", "D → E → C", "D → Ab → C"], a: 1, fb: "Avec la substitution tritonique : basse = Ré–Réb–Do. C'est une descente chromatique de 3 notes (D→Db→C). Cette ligne de basse est l'un des effets les plus caractéristiques du jazz moderne — le pianiste ou le bassiste peut créer cette voix intérieure qui descend par demi-tons." },
  { q: "Quel est l'avantage principal de la ligne de basse D–Db–C par rapport à D–G–C ?", opts: ["Elle est plus forte harmoniquement", "Elle est plus chromatique et lisse — meilleure conduite de voix", "Elle évite toute dissonance", "Elle est plus facile à chanter"], a: 1, fb: "D–Db–C est une descente chromatique de 3 notes consécutives (chaque note est un demi-ton plus bas). Cette continuité linéaire crée une sensation de 'glissement' très appréciée en jazz. D–G–C est plus fort harmoniquement mais moins lisse mélodiquement." },
  // Calcul des substitutions
  { q: "Quelle est la substitution tritonique de D7 ?", opts: ["G7", "Ab7", "Eb7", "A7"], a: 1, fb: "Ré + 6 demi-tons = Lab = Ab. La substitution tritonique de D7 est Ab7. Vérification : D7 contient F#–C (triton). Ab7 contient C–Gb/F# (même triton). ✓" },
  { q: "Quelle est la substitution tritonique de A7 ?", opts: ["Eb7", "D7", "Bb7", "E7"], a: 0, fb: "La + 6 demi-tons = Mi♭ = Eb. La substitution tritonique de A7 est Eb7. A7 contient C#–G (triton). Eb7 contient G–Db (= C#). Même triton, rôles inversés. ✓" },
  { q: "Quelle est la substitution tritonique de E7 ?", opts: ["B7", "Bb7", "A7", "F7"], a: 1, fb: "Mi + 6 demi-tons = Si♭ = Bb. La substitution tritonique de E7 est Bb7. E7 contient G#–D (triton). Bb7 contient D–Ab (= G#). ✓" },
  { q: "Quelle est la substitution tritonique de C7 ?", opts: ["F7", "G7", "F#7/Gb7", "Gb7 uniquement"], a: 2, fb: "Do + 6 demi-tons = Fa# = Gb. La substitution tritonique de C7 est F#7 (ou Gb7). C7 contient E–Bb (triton). Gb7 contient Bb–E. Même triton inversé. ✓" },
  { q: "Quelle est la substitution tritonique de F7 ?", opts: ["C7", "B7", "Gb7", "Bb7"], a: 1, fb: "Fa + 6 demi-tons = Si = B. La substitution tritonique de F7 est B7. F7 contient A–Eb (triton). B7 contient D#–A (= Eb–A). ✓" },
  { q: "Quelle est la substitution tritonique de Bb7 ?", opts: ["Eb7", "F7", "E7", "Ab7"], a: 2, fb: "Si♭ + 6 demi-tons = Mi = E. La substitution tritonique de Bb7 est E7. Bb7 contient D–Ab (triton). E7 contient G#–D (= Ab–D). ✓" },
  { q: "Si le triton sub de G7 est Db7, quel est le triton sub de Db7 ?", opts: ["G♭7", "G7", "Ab7", "C7"], a: 1, fb: "La relation est réciproque : si Db7 est le triton sub de G7, alors G7 est le triton sub de Db7. Réb + 6 = Sol. Chaque paire de substitutions tritoniques est symétrique — on peut substituer dans les deux sens." },
  // Applications jazz
  { q: "Dans Autumn Leaves, la cadence Am7♭5–D7–Gm avec substitution devient...", opts: ["Am7♭5–Ab7–Gm", "Am7♭5–G7–Gm", "Bm7♭5–Ab7–Gm", "Am7♭5–Db7–Gm"], a: 0, fb: "D7 → sub tritonique = Ab7 (Ré + 6 = Lab). Autumn Leaves : Am7♭5–D7–Gm avec sub → Am7♭5–Ab7–Gm. La ligne de basse A–Ab–G descend chromatiquement — très courant dans les arrangements jazz de ce standard." },
  { q: "La substitution tritonique peut s'appliquer à...", opts: ["uniquement le V7 principal", "n'importe quel accord de dominante 7te (y compris les dominantes secondaires)", "uniquement les accords majeurs", "uniquement en jazz bebop"], a: 1, fb: "Tout accord dominant 7te (contenant un triton interne) peut être substitué. Cela inclut les dominantes secondaires : V7/II (A7→Eb7), V7/IV (C7→Gb7), etc. C'est la raison pour laquelle la substitution tritonique est si polyvalente." },
  { q: "Dans un cycle II–V–I–IV–VII–III–VI, peut-on substituer tous les V7 ?", opts: ["Non — uniquement le V7 principal", "Oui — chaque dominant 7te peut être remplacé par son triton sub", "Oui, mais seulement les V7 impairs", "Non — cela briserait la tonalité"], a: 1, fb: "Oui. Dans un cycle de dominantes (ex : G7–C7–F7–Bb7 etc.), chaque accord peut être remplacé par son tritone sub : Db7–Gb7–B7–E7 etc. Cette 'chaîne de substitutions' crée une descente chromatique continue dans la basse — texture très jazz moderne." },
  { q: "La 'substitution de Coltrane' dans Giant Steps utilise...", opts: ["le même triton partagé", "un cycle de tierces majeures (divise l'octave en 3 parties égales)", "uniquement des dominantes secondaires", "des accords diminués"], a: 1, fb: "Les 'Coltrane changes' de Giant Steps (1960) étendent le concept de substitution avec un cycle de tierces majeures : B → G → E♭ (chacun à distance de tierce majeure = 4 demi-tons). Ce n'est pas directement la substitution tritonique, mais un développement harmonique voisin — diviser l'octave en 3 parties égales." },
  { q: "Dans Giant Steps, Coltrane passe par combien de centres tonaux différents en 2 mesures ?", opts: ["1", "2", "3", "4"], a: 2, fb: "Giant Steps progresse par 3 centres tonaux (B, G, E♭) en 2 mesures — un mouvement harmonique à une vitesse inouïe pour 1959. Chaque centre dure environ 2 temps. C'est ce que les musiciens de l'époque appelaient 'courir les changements' — il fallait improviser à une vitesse harmonique extrême." },
  { q: "Quel pianiste a enregistré Giant Steps avec Coltrane en 1960 ?", opts: ["Bill Evans", "Herbie Hancock", "Tommy Flanagan", "McCoy Tyner"], a: 2, fb: "Tommy Flanagan a joué piano sur Giant Steps (1960). L'histoire raconte qu'il était tellement surpris par l'harmonie de Coltrane lors de l'enregistrement qu'il a dû improviser 'de mémoire' — son solo est court car il ne maîtrisait pas encore les Coltrane changes." },
  { q: "La substitution tritonique est une technique principalement développée dans...", opts: ["la musique baroque", "le bebop et le jazz moderne (années 1940-1950)", "la musique Renaissance", "le jazz dixieland (années 1920)"], a: 1, fb: "La substitution tritonique est née dans le bebop (Charlie Parker, Dizzy Gillespie, Thelonious Monk, années 1940). Elle a été théorisée et systématisée dans les années 1950 avant d'être poussée à l'extrême par Coltrane dans les années 1960." },
  // Extensions sur le sub
  { q: "Sur Db7 (substitution de G7 → C), quelle est la 9te majeure ?", opts: ["Do", "Mi♭", "Fa", "Si♭"], a: 1, fb: "9te de Réb = 2de majeure à l'octave = Mi♭. Db9 = Réb–Fa–Lab–Do♭–Mi♭. La 9te (Mi♭) est disponible sur Db7 — elle résout vers Mi naturel dans CMaj7 par demi-ton ascendant. Excellent mouvement de voix !" },
  { q: "Sur Db7 → C, la 13te de Db7 est...", opts: ["Si♭", "Mi♭", "Si", "La♭"], a: 0, fb: "13te de Réb = 6te majeure = Si♭. Db13 contient Si♭ comme 13te. Si♭ → La (5te de C) = demi-ton descendant — belle résolution. La 13te (Bb/Si♭) est disponible sur Db7 car elle est à distance de ton de Lab (5te de Db7)." },
  { q: "La #11 de Db7 est...", opts: ["Sol", "Sol naturel (G)", "Fa#", "Mi♭"], a: 1, fb: "#11 de Réb = 4te augmentée = Sol naturel (G). Db7#11 contient Sol comme #11. Sol est la fondamentale de G7 — c'est une belle connexion harmonique entre les deux accords substitués. Db7#11 → CMaj7 est très courant en jazz." },
  { q: "Db7#11 → CMaj7 : la #11 (Sol) résout vers...", opts: ["Sol (reste en place dans CMaj7)", "Fa (5te de CMaj7)", "Mi (3ce de CMaj7)", "Ré (9te de CMaj9)"], a: 0, fb: "Sol est à la fois la #11 de Db7 et la quinte de CMaj7. La note reste en place lors de la résolution — c'est une 'common tone' (note commune) qui assure une continuité remarquable entre le sub et la résolution. Technique courante dans les arrangements jazz." },
  // Fonction harmonique
  { q: "La substitution tritonique préserve quelle fonction harmonique ?", opts: ["Tonique", "Sous-dominante", "Dominante (tension → résolution)", "Modale"], a: 2, fb: "Db7 reste un accord de dominante — il crée de la tension (via son triton interne B–F = Cb–F) qui se résout vers C. La fonction dominante est préservée même si la basse change. C'est ce qui rend la substitution harmoniquement cohérente." },
  { q: "Le degré de Db7 dans la gamme de Do majeur est...", opts: ["♭II7 (second degré bémolisé)", "IV7", "VI7", "♭VII7"], a: 0, fb: "Réb est le IIe degré bémolisé de Do majeur (♭II). Db7 utilisé comme substitution tritonique de G7 est donc noté ♭II7 dans l'analyse fonctionnelle. Ce mouvement ♭II7→I est appelé 'résolution napolitaine' dans certaines analyses — bien que le mécanisme jazz soit différent de l'accord napolitain classique." },
  { q: "La substitution tritonique de la dominante secondaire V7/II (A7) en Do est...", opts: ["D7", "Eb7", "E♭7", "Eb7 (= Mi♭7)"], a: 3, fb: "A7 (dominante de Dm) + 6 demi-tons = Eb7. La substitution tritonique de A7 est Eb7. Dans une progression Dm7–A7–G7, on peut substituer : Dm7–Eb7–G7 ou Dm7–Eb7–Db7, créant une descente chromatique Mi♭→Ré♭→Do." },
  { q: "La résolution Db7 → CMaj7 est parfois comparée à la cadence napolitaine car...", opts: ["les deux utilisent un accord sur ♭II", "les deux sont des cadences parfaites", "les deux proviennent du baroque", "les deux utilisent le triton"], a: 0, fb: "L'accord napolitain (♭II6 classique) et la substitution tritonique Db7 partagent le fait d'utiliser un accord dont la fondamentale est ♭II (Réb en Do). Les mécanismes diffèrent (voix leading classique vs triton jazz), mais la fonction ♭II→I est commune." },
  // Voix leading
  { q: "La substitution tritonique améliore la conduite de voix car...", opts: ["elle supprime toutes les dissonances", "elle crée des mouvements par demi-tons (voix leading chromatique) au lieu de sauts de quinte", "elle simplifie l'harmonie", "elle évite le triton"], a: 1, fb: "Les sauts de quinte (G→C) créent une progression forte mais avec de grands intervalles. La substitution tritonique (Db→C) remplace le saut de quinte par un demi-ton, améliorant la linéarité et la fluidité des voix. C'est le voix leading chromatique (chromatic voice leading) du jazz." },
  { q: "Dans la substitution Db7→CMaj7, combien de voix se déplacent par demi-ton ?", opts: ["1", "2", "3", "0"], a: 2, fb: "3 voix bougent par demi-ton : Réb→Do (basse, ½ ton), Fa→Mi (3ce de Db7 → 3ce de CMaj7, ½ ton), Si→Do (♭7te de Db7 → fondamentale de CMaj7, ½ ton ascendant). Seul Lab (5te de Db7) doit sauter vers Sol (quinte de CMaj7). Voix leading exceptionnel !" },
  { q: "Dans la résolution G7→CMaj7 (standard), combien de voix se déplacent par demi-ton ?", opts: ["0", "1", "2", "3"], a: 2, fb: "G7→CMaj7 : Si→Do (½ ton, sensible vers tonique) et Fa→Mi (½ ton, ♭7te vers 3ce). Le Sol (basse) saute à Do (quinte). Ré peut sauter vers Sol ou Do. Deux mouvements par demi-ton — moins lisse que la substitution (3 demi-tons)." },
  // Coltrane avancé
  { q: "Les 'Coltrane changes' divisent l'octave en...", opts: ["2 parties égales (tritons)", "3 parties égales (tierces majeures)", "4 parties égales (tierces mineures)", "6 parties égales (tons entiers)"], a: 1, fb: "Les Coltrane changes divisent l'octave en 3 parties égales par tierces majeures (4 demi-tons chacune) : B → G → E♭ → B (retour). Chaque division de tierce majeure génère un centre tonal temporaire. Ce cycle par tierces majeures est aussi appelé 'mouvement de Coltrane' ou 'cadence de Coltrane'." },
  { q: "Quel album de John Coltrane (1960) a révolutionné l'harmonie jazz ?", opts: ["A Love Supreme", "Kind of Blue", "Giant Steps", "My Favorite Things"], a: 2, fb: "Giant Steps (1960) est l'album qui a introduit les 'Coltrane changes' — une progression harmonique par tierces majeures à une vitesse inouïe. Le titre track 'Giant Steps' est devenu l'un des standards jazz les plus difficiles à improviser." },
  { q: "Le saxophone de Coltrane sur 'A Love Supreme' (1964) utilise plutôt...", opts: ["des Coltrane changes rapides", "un style modal plus statique sur des vamps", "la substitution tritonique systématique", "des gammes pentatoniques uniquement"], a: 1, fb: "A Love Supreme (1964) est plus modal — inspiré par Kind of Blue de Miles Davis. Coltrane utilise ici de longues improvisations sur des vamps modaux plutôt que des progressions harmoniques complexes. C'est un équilibre entre son approche harmonique de Giant Steps et le jazz modal." },
  // Ear training
  { q: "À l'oreille, Db7→C sonne par rapport à G7→C...", opts: ["Plus abrupt et fort", "Plus lisse et chromatique — sensation de 'glissement'", "Identique", "Plus dissonant"], a: 1, fb: "Db7→C sonne plus lisse car la basse descend par demi-ton (Réb→Do). La résolution semble 'glisser' vers la tonique plutôt que d'y 'tomber' (comme dans G→C par quinte). Le résultat est plus surprenant et sophistiqué — signature du jazz moderne." },
  { q: "La basse Réb→Do dans Db7→C crée un intervalle de...", opts: ["seconde majeure (ton)", "seconde mineure (demi-ton)", "tierce mineure", "quinte"], a: 1, fb: "Réb→Do = seconde mineure = demi-ton = 1 demi-ton. C'est le plus petit intervalle de la gamme tempérée occidentale. La résolution par demi-ton descendant est la plus lisse possible — d'où l'effet de 'glissement chromatique' très recherché en jazz." },
  { q: "La basse Sol→Do dans G7→C crée un intervalle de...", opts: ["quarte juste (ascendant)", "quinte juste (descendant)", "tierce majeure", "sixte"], a: 1, fb: "Sol→Do descendant = quinte juste (7 demi-tons). Sol→Do ascendant = quarte juste. En termes de mouvement de basse, on dit 'descente de quinte' (G down to C). C'est le mouvement cadentiel le plus fort de la tonalité." },
  { q: "Peut-on entendre G7 et Db7 utilisés ensemble dans la même mesure ?", opts: ["Non — ils s'excluent mutuellement", "Oui — souvent comme accords de passage chromatiques (G7–Db7–C)", "Oui, mais uniquement en mode mineur", "Non — ils ont le même triton donc sonnent pareils"], a: 1, fb: "G7 et Db7 peuvent coexister comme accords de passage chromatiques : G7–Db7–CMaj7 en une seule progression. La basse descend G→Db→C par triton puis demi-ton. On voit aussi G7–G♭7–C (♭V7 comme passing chord) dans certains arrangements." },
  // Applications avancées
  { q: "Le 'backdoor dominant' (♭VII7→I, ex: Bb7→C) est-il lié à la substitution tritonique ?", opts: ["Non — mécanisme complètement différent", "Oui — Bb7 est le triton sub de E7, pas de G7 (mécanismes voisins mais distincts)", "Oui — c'est exactement la même chose", "Non — le backdoor n'utilise pas de triton"], a: 1, fb: "Le backdoor dominant (Bb7→C = ♭VII7→I) utilise un accord à distance de ton de la tonique, pas de triton. C'est un mécanisme harmonique voisin (résolution par glissement) mais distinct de la substitution tritonique. Ils partagent cependant l'idée de résoudre vers I depuis un accord non-conventionnel." },
  { q: "Dans un blues en La, la cadence IV7–I7 (D7–A7) avec substitution devient...", opts: ["D7–Eb7", "Ab7–A7", "Ab7–Eb7", "D7–Ab7"], a: 3, fb: "D7 (IV7 en La) n'est pas habituellement substitué dans ce contexte. Mais A7 (I7 en blues) → La + 6 = Mi♭. Substitution de A7 = Eb7. Dans le blues, la substitution tritonique s'applique surtout aux V7 (E7→La) : E7 → Bb7. Bb7→A crée une résolution chromatique par ½ ton." },
  { q: "La substitution tritonique peut-elle s'appliquer au IVMaj7 (sous-dominant majeur) ?", opts: ["Oui — FMaj7 peut être substitué par BMaj7", "Non — le IVMaj7 n'a pas de triton instable à résoudre", "Oui, mais seulement en jazz fusion", "Non — le IVMaj7 est toujours stable"], a: 1, fb: "Non. La substitution tritonique ne s'applique qu'aux accords de dominante 7te (contenant un triton instable). Un accord IVMaj7 (FMaj7) a une 7te majeure — son triton interne est différent et n'a pas la même urgence de résolution. Le concept de sub est lié à la tension dominante." },
  { q: "Charlie Parker utilisait souvent dans ses improvisations...", opts: ["des gammes pentatoniques uniquement", "des 'substitutions' et des 'turnarounds' avec les triton subs pour créer des lignes chromatiques", "uniquement la gamme majeure", "des accords de quartes empilées"], a: 1, fb: "Charlie Parker ('Bird') était un maître des substitutions harmoniques — il improvisait sur G7–Db7–C en temps réel, créant des lignes bebop très chromatiques. Il a dit : 'Si vous ne vivez pas dans l'harmonie, vous serez toujours en dehors.' Les triton subs sont au cœur du bebop." },
  { q: "Miles Davis dans 'Round Midnight' (arrangement) utilise des substitutions pour...", opts: ["simplifier les accords originaux de Monk", "enrichir les changements de Monk avec des substitutions chromatiques", "éviter les accords diminués", "transposer le morceau dans une autre tonalité"], a: 1, fb: "Miles Davis et Gil Evans ont enrichi 'Round Midnight' (originalement de Monk) avec de nombreuses substitutions, notamment tritoniques, créant une texture harmonique plus dense. C'est un exemple parfait de réharmonisation jazz utilisant les tritone subs." },
  { q: "La relation entre G7 et Db7 peut aussi être vue comme...", opts: ["une modulation distante", "deux accords à distance d'un triton dont les rôles de guide tones s'inversent", "deux accords ayant la même fondamentale", "deux accords ayant la même 5te"], a: 1, fb: "G7 et Db7 sont à distance d'un triton (6 demi-tons) l'un de l'autre. Leurs guide tones (B/Cb et F) sont exactement les mêmes, avec les rôles inversés (3ce ↔ 7te). C'est une symétrie harmonique élégante au cœur du triton sub." },
];

// English translations — add when available; until then falls back to fr


const questionsPt: Question[] = [{ q: "Um trítono é um intervalo de...", opts: ["5 semitons", "6 semitons", "7 semitons", "4 semitons"], a: 1, fb: "O trítono = 6 semitons = quarta aumentada = quinta diminuta. É o intervalo mais dissonante da escala temperada — divide a oitava (12 semitons) exatamente ao meio. Ex: C → F# = 6 semitons." },
{ q: "Por que o trítono é chamado de 'diabolus in musica' na Idade Média?", opts: ["Era fácil de tocar", "Era o intervalo mais consonante", "Sua extrema dissonância era considerada perigosa e era proibida", "Lembrava o som de um diabo"], a: 2, fb: "Na Idade Média e no Renascimento, o trítono era explicitamente proibido na música religiosa por causa de sua dissonância. 'Diabolus in musica' (diabo na música) é uma expressão que data do tratado de Johannes de Muris (século XIV)." },
{ q: "O trítono de G é...", opts: ["D", "C#", "Db", "A"], a: 2, fb: "G → Db = 6 semitons. G=7, +6=13=Db. É por isso que Db7 é a substituição tritônica de G7." },
{ q: "O trítono de C é...", opts: ["G", "F#", "Bb", "A#"], a: 1, fb: "C → F# = 6 semitons. C=0, +6=F#(Gb). A substituição tritônica de C7 é F#7 (ou Gb7 dependendo do contexto)." },
{ q: "O trítono de D é...", opts: ["G#", "Ab", "G#/Ab (enarmônicos)", "G"], a: 2, fb: "D + 6 semitons = G# = Ab (notas enarmônicas). As duas notações são equivalentes. A substituição tritônica de D7 é Ab7." },
{ q: "Quantos pares de substituições tritônicas existem nas 12 tonalidades?", opts: ["6 pares", "12 pares", "24 pares", "3 pares"], a: 0, fb: "Existem 6 pares de substituições tritônicas: G7↔Db7, D7↔Ab7, A7↔Eb7, E7↔Bb7, B7↔F7, F#7↔C7. Cada par compartilha o mesmo trítono interno (as guide tones)." },
{ q: "G7 contém o trítono B – F. Em Db7, essas mesmas notas são...", opts: ["A 9ª e a 5ª", "A ♭7ª (Cb=B) e a 3ª (F)", "A 3ª e a quinta", "A fundamental e a 9ª"], a: 1, fb: "Em Db7: a 3ª é F e a ♭7ª é Cb (= B natural enarmonicamente). O trítono F–B é compartilhado entre G7 e Db7, mas os papéis se invertem: B (3ª de G7) torna-se ♭7 de Db7; F (♭7 de G7) torna-se 3ª de Db7." },
{ q: "As 'guide tones' de um acorde são...", opts: ["a fundamental e a 5ª", "a 3ª e a 7ª", "a 9ª e a 13ª", "a fundamental e a 9ª"], a: 1, fb: "As guide tones = 3ª + 7ª. São as notas que definem a qualidade (maior/menor) e a tensão (dominante/Maj7) de um acorde. A fundamental e a 5ª são acusticamente redundantes; a 3ª e a 7ª carregam toda a informação harmônica." },
{ q: "Na substituição tritônica, as guide tones...", opts: ["desaparecem completamente", "permanecem idênticas mas trocam seus papéis (3ª ↔ 7ª)", "se deslocam um semitom", "dobram de oitava"], a: 1, fb: "Este é o segredo da substituição tritônica: as duas notas do trítono permanecem presentes, mas seus papéis se invertem. A 3ª de G7 (B) torna-se a ♭7ª de Db7 (Cb). A ♭7ª de G7 (F) torna-se a 3ª de Db7 (F). Os dois acordes resolvem para C pela mesma razão: compartilham o mesmo trítono instável." },
{ q: "Por que G7 e Db7 resolvem ambos para C maior?", opts: ["Por convenção histórica apenas", "Porque compartilham o mesmo trítono interno (B–F = Cb–F) que resolve para C", "Porque têm a mesma fundamental", "Porque têm a mesma 5ª"], a: 1, fb: "G7 e Db7 compartilham as notas B (=Cb) e F — o trítono. Esse trítono resolve para C e E (B→C semitom ascendente, F→E semitom descendente). Independentemente de a baixo ser G ou Db, as guide tones resolvem identicamente para CMaj7." },
{ q: "A resolução do trítono B–F para C–E implica...", opts: ["B sobe um semitom para C; F desce um semitom para E", "B desce para A; F sobe para G", "B e F ficam no lugar", "B sobe um tom para C#; F desce um tom para Eb"], a: 0, fb: "B → C (semitom ascendente) e F → E (semitom descendente). Esses dois movimentos de semitom convergem para a tônica C e sua 3ª E. É essa atração do trítono em direção à terça maior da tônica que gera a tensão → resolução." },
{ q: "A cadência padrão G7 → C implica qual movimento de baixo?", opts: ["Cromático descendente (G→Gb→F→E→...→C)", "Descida de quinta (G desce para C = descida de quinta justa)", "Subida de quarta", "Permanece em G"], a: 1, fb: "G7 → C: o baixo desce uma quinta justa (7 semitons) de G para C. Esse movimento de quinta descendente (ou subida de quarta) é o movimento cadencial mais forte da tonalidade — a razão pela qual V→I é a resolução arquetípica." },
{ q: "A cadência tritônica Db7 → C implica qual movimento de baixo?", opts: ["Descida de quinta (Db → Gb)", "Subida de um semitom (Db→D)", "Descida de um semitom cromático (Db→C)", "Permanece em Db"], a: 2, fb: "Db7 → C: o baixo desce um semitom de Db para C. É o movimento cromático mais suave possível. Essa resolução por deslizamento (em vez de salto de quinta) é a principal vantagem da substituição tritônica: suavidade e cromatismo." },
{ q: "No II-V-I padrão (Dm7–G7–CMaj7), a linha de baixo é...", opts: ["D → Db → C (cromática)", "D → G → C (quintas descendentes)", "D → E → C", "D → A → C"], a: 1, fb: "Dm7–G7–CMaj7 em C: baixo = D–G–C. D→G = quinta descendente (ou quarta ascendente); G→C = quinta descendente. Progressão pelo ciclo de quintas — muito forte harmonicamente, menos suave linearmente." },
{ q: "No II-V-I com substituição (Dm7–Db7–CMaj7), a linha de baixo é...", opts: ["D → G → C", "D → Db → C (descida cromática!)", "D → E → C", "D → Ab → C"], a: 1, fb: "Com a substituição tritônica: baixo = D–Db–C. É uma descida cromática de 3 notas (D→Db→C). Essa linha de baixo é um dos efeitos mais característicos do jazz moderno — o pianista ou o contrabaixista pode criar essa voz interna que desce por semitons." },
{ q: "Qual é a principal vantagem da linha de baixo D–Db–C em relação a D–G–C?", opts: ["É harmonicamente mais forte", "É mais cromática e suave — melhor condução de vozes", "Evita toda dissonância", "É mais fácil de cantar"], a: 1, fb: "D–Db–C é uma descida cromática de 3 notas consecutivas (cada nota um semitom abaixo). Essa continuidade linear cria uma sensação de 'deslizamento' muito apreciada no jazz. D–G–C é harmonicamente mais forte, mas melodicamente menos suave." },
{ q: "Qual é a substituição tritônica de D7?", opts: ["G7", "Ab7", "Eb7", "A7"], a: 1, fb: "D + 6 semitons = Ab. A substituição tritônica de D7 é Ab7. Verificação: D7 contém F#–C (trítono). Ab7 contém C–Gb/F# (mesmo trítono). ✓" },
{ q: "Qual é a substituição tritônica de A7?", opts: ["Eb7", "D7", "Bb7", "E7"], a: 0, fb: "A + 6 semitons = Eb. A substituição tritônica de A7 é Eb7. A7 contém C#–G (trítono). Eb7 contém G–Db (= C#). Mesmo trítono, papéis invertidos. ✓" },
{ q: "Qual é a substituição tritônica de E7?", opts: ["B7", "Bb7", "A7", "F7"], a: 1, fb: "E + 6 semitons = Bb. A substituição tritônica de E7 é Bb7. E7 contém G#–D (trítono). Bb7 contém D–Ab (= G#). ✓" },
{ q: "Qual é a substituição tritônica de C7?", opts: ["F7", "G7", "F#7/Gb7", "Gb7 apenas"], a: 2, fb: "C + 6 semitons = F# = Gb. A substituição tritônica de C7 é F#7 (ou Gb7). C7 contém E–Bb (trítono). Gb7 contém Bb–E. Mesmo trítono invertido. ✓" },
{ q: "Qual é a substituição tritônica de F7?", opts: ["C7", "B7", "Gb7", "Bb7"], a: 1, fb: "F + 6 semitons = B. A substituição tritônica de F7 é B7. F7 contém A–Eb (trítono). B7 contém D#–A (= Eb–A). ✓" },
{ q: "Qual é a substituição tritônica de Bb7?", opts: ["Eb7", "F7", "E7", "Ab7"], a: 2, fb: "Bb + 6 semitons = E. A substituição tritônica de Bb7 é E7. Bb7 contém D–Ab (trítono). E7 contém G#–D (= Ab–D). ✓" },
{ q: "Se o triton sub de G7 é Db7, qual é o triton sub de Db7?", opts: ["Gb7", "G7", "Ab7", "C7"], a: 1, fb: "A relação é recíproca: se Db7 é o triton sub de G7, então G7 é o triton sub de Db7. Db + 6 = G. Cada par de substituições tritônicas é simétrico — pode-se substituir nos dois sentidos." },
{ q: "Em Autumn Leaves, a cadência Am7♭5–D7–Gm com substituição torna-se...", opts: ["Am7♭5–Ab7–Gm", "Am7♭5–G7–Gm", "Bm7♭5–Ab7–Gm", "Am7♭5–Db7–Gm"], a: 0, fb: "D7 → sub tritônica = Ab7 (D + 6 = Ab). Autumn Leaves: Am7♭5–D7–Gm com sub → Am7♭5–Ab7–Gm. A linha de baixo A–Ab–G desce cromaticamente — muito comum nos arranjos jazz desse standard." },
{ q: "A substituição tritônica pode ser aplicada a...", opts: ["apenas o V7 principal", "qualquer acorde de dominante 7ª (incluindo dominantes secundárias)", "apenas acordes maiores", "apenas no jazz bebop"], a: 1, fb: "Todo acorde dominante 7ª (contendo um trítono interno) pode ser substituído. Isso inclui as dominantes secundárias: V7/II (A7→Eb7), V7/IV (C7→Gb7), etc. É por isso que a substituição tritônica é tão versátil." },
{ q: "Em um ciclo II–V–I–IV–VII–III–VI, pode-se substituir todos os V7?", opts: ["Não — apenas o V7 principal", "Sim — cada dominante 7ª pode ser substituída pelo seu triton sub", "Sim, mas apenas os V7 ímpares", "Não — isso quebraria a tonalidade"], a: 1, fb: "Sim. Em um ciclo de dominantes (ex: G7–C7–F7–Bb7 etc.), cada acorde pode ser substituído pelo seu tritone sub: Db7–Gb7–B7–E7 etc. Essa 'cadeia de substituições' cria uma descida cromática contínua no baixo — textura muito característica do jazz moderno." },
{ q: "A 'substituição de Coltrane' em Giant Steps utiliza...", opts: ["o mesmo trítono compartilhado", "um ciclo de terças maiores (divide a oitava em 3 partes iguais)", "apenas dominantes secundárias", "acordes diminutos"], a: 1, fb: "Os 'Coltrane changes' de Giant Steps (1960) estendem o conceito de substituição com um ciclo de terças maiores: B → G → Eb (cada uma a uma distância de terça maior = 4 semitons). Não é diretamente a substituição tritônica, mas um desenvolvimento harmônico relacionado — dividir a oitava em 3 partes iguais." },
{ q: "Em Giant Steps, Coltrane passa por quantos centros tonais diferentes em 2 compassos?", opts: ["1", "2", "3", "4"], a: 2, fb: "Giant Steps progride por 3 centros tonais (B, G, Eb) em 2 compassos — um movimento harmônico em velocidade inédita para 1959. Cada centro dura cerca de 2 tempos. É o que os músicos da época chamavam de 'correr as mudanças' — era preciso improvisar em uma velocidade harmônica extrema." },
{ q: "Qual pianista gravou Giant Steps com Coltrane em 1960?", opts: ["Bill Evans", "Herbie Hancock", "Tommy Flanagan", "McCoy Tyner"], a: 2, fb: "Tommy Flanagan tocou piano em Giant Steps (1960). A história conta que ele ficou tão surpreso com a harmonia de Coltrane durante a gravação que teve de improvisar 'de memória' — seu solo é curto porque ele ainda não dominava os Coltrane changes." },
{ q: "A substituição tritônica é uma técnica desenvolvida principalmente no...", opts: ["período barroco", "bebop e jazz moderno (anos 1940–1950)", "período renascentista", "jazz dixieland (anos 1920)"], a: 1, fb: "A substituição tritônica nasceu no bebop (Charlie Parker, Dizzy Gillespie, Thelonious Monk, anos 1940). Foi teorizada e sistematizada nos anos 1950, antes de ser levada ao extremo por Coltrane nos anos 1960." },
{ q: "Em Db7 (substituição de G7 → C), qual é a 9ª maior?", opts: ["C", "Eb", "F", "Bb"], a: 1, fb: "9ª de Db = 2ª maior na oitava = Eb. Db9 = Db–F–Ab–Cb–Eb. A 9ª (Eb) está disponível em Db7 — ela resolve para E natural em CMaj7 por semitom ascendente. Excelente condução de voz!" },
{ q: "Em Db7 → C, a 13ª de Db7 é...", opts: ["Bb", "Eb", "B", "Ab"], a: 0, fb: "13ª de Db = 6ª maior = Bb. Db13 contém Bb como 13ª. Bb → A (5ª de C) = semitom descendente — bela resolução. A 13ª (Bb) está disponível em Db7 pois está a um tom de distância de Ab (5ª de Db7)." },
{ q: "A #11 de Db7 é...", opts: ["G", "G natural", "F#", "Eb"], a: 1, fb: "#11 de Db = 4ª aumentada = G natural. Db7#11 contém G como #11. G é a fundamental de G7 — uma bela conexão harmônica entre os dois acordes substituídos. Db7#11 → CMaj7 é muito comum no jazz." },
{ q: "Db7#11 → CMaj7: a #11 (G) resolve para...", opts: ["G (permanece em CMaj7)", "F (5ª de CMaj7)", "E (3ª de CMaj7)", "D (9ª de CMaj9)"], a: 0, fb: "G é ao mesmo tempo a #11 de Db7 e a quinta de CMaj7. A nota permanece no lugar durante a resolução — é uma 'common tone' (nota comum) que garante uma continuidade notável entre o sub e a resolução. Técnica comum nos arranjos jazz." },
{ q: "A substituição tritônica preserva qual função harmônica?", opts: ["Tônica", "Subdominante", "Dominante (tensão → resolução)", "Modal"], a: 2, fb: "Db7 continua sendo um acorde de dominante — cria tensão (por meio do trítono interno B–F = Cb–F) que resolve para C. A função dominante é preservada mesmo que o baixo mude. É isso que torna a substituição harmonicamente coerente." },
{ q: "O grau de Db7 na escala de C maior é...", opts: ["♭II7 (segundo grau bemolizado)", "IV7", "VI7", "♭VII7"], a: 0, fb: "Db é o II grau bemolizado de C maior (♭II). Db7 usado como substituição tritônica de G7 é portanto notado ♭II7 na análise funcional. Esse movimento ♭II7→I é chamado de 'resolução napolitana' em algumas análises — embora o mecanismo jazz seja diferente do acorde napolitano clássico." },
{ q: "A substituição tritônica da dominante secundária V7/II (A7) em C é...", opts: ["D7", "Eb7", "E♭7", "Eb7 (= Mi♭7)"], a: 3, fb: "A7 (dominante de Dm) + 6 semitons = Eb7. A substituição tritônica de A7 é Eb7. Em uma progressão Dm7–A7–G7, pode-se substituir: Dm7–Eb7–G7 ou Dm7–Eb7–Db7, criando uma descida cromática Eb→Db→C." },
{ q: "A resolução Db7 → CMaj7 é às vezes comparada à cadência napolitana porque...", opts: ["ambas usam um acorde sobre ♭II", "ambas são cadências perfeitas", "ambas vêm do barroco", "ambas usam o trítono"], a: 0, fb: "O acorde napolitano (♭II6 clássico) e a substituição tritônica Db7 compartilham o fato de usar um acorde cuja fundamental é ♭II (Db em C). Os mecanismos diferem (condução de vozes clássica vs trítono jazz), mas a função ♭II→I é comum." },
{ q: "A substituição tritônica melhora a condução de vozes porque...", opts: ["elimina todas as dissonâncias", "cria movimentos por semitons (condução de voz cromática) em vez de saltos de quinta", "simplifica a harmonia", "evita o trítono"], a: 1, fb: "Os saltos de quinta (G→C) criam uma progressão forte, mas com grandes intervalos. A substituição tritônica (Db→C) substitui o salto de quinta por um semitom, melhorando a linearidade e a fluidez das vozes. É o voice leading cromático (chromatic voice leading) do jazz." },
{ q: "Na substituição Db7→CMaj7, quantas vozes se movem por semitom?", opts: ["1", "2", "3", "0"], a: 2, fb: "3 vozes se movem por semitom: Db→C (baixo, ½ tom), F→E (3ª de Db7 → 3ª de CMaj7, ½ tom), B→C (♭7ª de Db7 → fundamental de CMaj7, ½ tom ascendente). Apenas Ab (5ª de Db7) precisa saltar para G (quinta de CMaj7). Voice leading excepcional!" },
{ q: "Na resolução G7→CMaj7 (padrão), quantas vozes se movem por semitom?", opts: ["0", "1", "2", "3"], a: 2, fb: "G7→CMaj7: B→C (½ tom, sensível → tônica) e F→E (½ tom, ♭7ª → 3ª). G (baixo) salta para C (quinta). D pode saltar para G ou C. Dois movimentos por semitom — menos suave que a substituição (3 semitons)." },
{ q: "Os 'Coltrane changes' dividem a oitava em...", opts: ["2 partes iguais (trítonos)", "3 partes iguais (terças maiores)", "4 partes iguais (terças menores)", "6 partes iguais (tons inteiros)"], a: 1, fb: "Os Coltrane changes dividem a oitava em 3 partes iguais por terças maiores (4 semitons cada): B → G → Eb → B (retorno). Cada divisão de terça maior gera um centro tonal temporário. Esse ciclo por terças maiores também é chamado de 'movimento de Coltrane' ou 'cadência de Coltrane'." },
{ q: "Qual álbum de John Coltrane (1960) revolucionou a harmonia do jazz?", opts: ["A Love Supreme", "Kind of Blue", "Giant Steps", "My Favorite Things"], a: 2, fb: "Giant Steps (1960) é o álbum que introduziu os 'Coltrane changes' — uma progressão harmônica por terças maiores em velocidade inédita. A faixa-título 'Giant Steps' tornou-se um dos standards de jazz mais difíceis de improvisar." },
{ q: "O saxofone de Coltrane em 'A Love Supreme' (1964) utiliza principalmente...", opts: ["Coltrane changes rápidos", "um estilo modal mais estático sobre vamps", "substituição tritônica sistemática", "apenas escalas pentatônicas"], a: 1, fb: "A Love Supreme (1964) é mais modal — inspirado por Kind of Blue de Miles Davis. Coltrane usa aqui longas improvisações sobre vamps modais em vez de progressões harmônicas complexas. É um equilíbrio entre sua abordagem harmônica de Giant Steps e o jazz modal." },
{ q: "Ao ouvido, Db7→C soa em relação a G7→C...", opts: ["Mais abrupto e forte", "Mais suave e cromático — sensação de 'deslizamento'", "Idêntico", "Mais dissonante"], a: 1, fb: "Db7→C soa mais suave porque o baixo desce por semitom (Db→C). A resolução parece 'deslizar' em direção à tônica em vez de 'cair' sobre ela (como em G→C por quinta). O resultado é mais surpreendente e sofisticado — marca registrada do jazz moderno." },
{ q: "O baixo Db→C em Db7→C cria um intervalo de...", opts: ["segunda maior (tom)", "segunda menor (semitom)", "terça menor", "quinta"], a: 1, fb: "Db→C = segunda menor = semitom = 1 semitom. É o menor intervalo da escala temperada ocidental. A resolução por semitom descendente é a mais suave possível — daí o efeito de 'deslizamento cromático' muito valorizado no jazz." },
{ q: "O baixo G→C em G7→C cria um intervalo de...", opts: ["quarta justa (ascendente)", "quinta justa (descendente)", "terça maior", "sexta"], a: 1, fb: "G→C descendente = quinta justa (7 semitons). G→C ascendente = quarta justa. Em termos de movimento de baixo, diz-se 'descida de quinta' (G desce para C). É o movimento cadencial mais forte da tonalidade." },
{ q: "É possível ouvir G7 e Db7 utilizados juntos no mesmo compasso?", opts: ["Não — eles se excluem mutuamente", "Sim — frequentemente como acordes de passagem cromáticos (G7–Db7–C)", "Sim, mas apenas em modo menor", "Não — têm o mesmo trítono, portanto soam igual"], a: 1, fb: "G7 e Db7 podem coexistir como acordes de passagem cromáticos: G7–Db7–CMaj7 em uma única progressão. O baixo desce G→Db→C por trítono e depois semitom. Também se vê G7–G♭7–C (♭V7 como passing chord) em alguns arranjos." },
{ q: "O 'backdoor dominant' (♭VII7→I, ex: Bb7→C) está relacionado à substituição tritônica?", opts: ["Não — mecanismo completamente diferente", "Sim — Bb7 é o triton sub de E7, não de G7 (mecanismos próximos, mas distintos)", "Sim — é exatamente a mesma coisa", "Não — o backdoor não usa trítono"], a: 1, fb: "O backdoor dominant (Bb7→C = ♭VII7→I) usa um acorde a um tom de distância da tônica, não um trítono. É um mecanismo harmônico próximo (resolução por deslizamento), mas distinto da substituição tritônica. Compartilham, porém, a ideia de resolver para I a partir de um acorde não convencional." },
{ q: "Em um blues em A, a cadência IV7–I7 (D7–A7) com substituição torna-se...", opts: ["D7–Eb7", "Ab7–A7", "Ab7–Eb7", "D7–Ab7"], a: 3, fb: "D7 (IV7 em A) não é habitualmente substituído nesse contexto. Mas A7 (I7 no blues) → A + 6 = Eb. Substituição de A7 = Eb7. No blues, a substituição tritônica se aplica principalmente ao V7 (E7→A): E7 → Bb7. Bb7→A cria uma resolução cromática por ½ tom." },
{ q: "A substituição tritônica pode ser aplicada ao IVMaj7 (subdominante maior)?", opts: ["Sim — FMaj7 pode ser substituído por BMaj7", "Não — o IVMaj7 não tem trítono instável para resolver", "Sim, mas apenas no jazz fusion", "Não — o IVMaj7 é sempre estável"], a: 1, fb: "Não. A substituição tritônica se aplica apenas a acordes de dominante 7ª (contendo um trítono instável). Um acorde IVMaj7 (FMaj7) tem uma 7ª maior — seu trítono interno é diferente e não tem a mesma urgência de resolução. O conceito de sub está ligado à tensão dominante." },
{ q: "Charlie Parker frequentemente usava em suas improvisações...", opts: ["apenas escalas pentatônicas", "'substituições' e 'turnarounds' com triton subs para criar linhas cromáticas", "apenas a escala maior", "acordes de quartas empilhadas"], a: 1, fb: "Charlie Parker ('Bird') era um mestre das substituições harmônicas — improvisava sobre G7–Db7–C em tempo real, criando linhas bebop muito cromáticas. Ele disse: 'Se você não vive na harmonia, estará sempre por fora.' Os triton subs são o coração do bebop." },
{ q: "Miles Davis em ''Round Midnight' (arranjo) usa substituições para...", opts: ["simplificar os acordes originais de Monk", "enriquecer as mudanças de Monk com substituições cromáticas", "evitar os acordes diminutos", "transpor a música para outra tonalidade"], a: 1, fb: "Miles Davis e Gil Evans enriqueceram ''Round Midnight' (originalmente de Monk) com inúmeras substituições, especialmente tritônicas, criando uma textura harmônica mais densa. É um exemplo perfeito de reharmonização jazz utilizando os tritone subs." },
{ q: "A relação entre G7 e Db7 também pode ser vista como...", opts: ["uma modulação distante", "dois acordes a distância de um trítono cujos papéis de guide tones se invertem", "dois acordes com a mesma fundamental", "dois acordes com a mesma 5ª"], a: 1, fb: "G7 e Db7 estão a distância de um trítono (6 semitons) um do outro. Suas guide tones (B/Cb e F) são exatamente as mesmas, com os papéis invertidos (3ª ↔ 7ª). É uma elegante simetria harmônica no coração do triton sub." },
];

const questionsEn: Question[] = [{ q: "A tritone is an interval of...", opts: ["5 semitones", "6 semitones", "7 semitones", "4 semitones"], a: 1, fb: "The tritone = 6 semitones = augmented fourth = diminished fifth. It is the most dissonant interval in the equal-tempered scale — it divides the octave (12 semitones) exactly in half. Ex: C → F# = 6 semitones." },
{ q: "Why was the tritone called 'diabolus in musica' in the Middle Ages?", opts: ["It was easy to play", "It was the most consonant interval", "Its extreme dissonance was considered dangerous and was forbidden", "It resembled the sound of a devil"], a: 2, fb: "In the Middle Ages and Renaissance, the tritone was explicitly forbidden in church music because of its dissonance. 'Diabolus in musica' (the devil in music) is an expression dating back to the treatise of Johannes de Muris (14th century)." },
{ q: "The tritone of G is...", opts: ["D", "C#", "Db", "A"], a: 2, fb: "G → Db = 6 semitones (G=7, G#=8, A=9, Bb=10, B=11, C=12, Db=13... starting from C=0: G=7, +6=13=Db at the upper octave). G + 6 = Db. That is why Db7 is the tritone substitution of G7." },
{ q: "The tritone of C is...", opts: ["G", "F#", "Bb", "A#"], a: 1, fb: "C → F# = 6 semitones. C=0, +6=F#(Gb). The tritone substitution of C7 is F#7 (or Gb7 depending on context)." },
{ q: "The tritone of D is...", opts: ["G#", "Ab", "G#/Ab (enharmonics)", "G"], a: 2, fb: "D + 6 semitones = G# = Ab (enharmonic notes). Both spellings are equivalent. The tritone substitution of D7 is Ab7." },
{ q: "How many pairs of tritone substitutions exist across the 12 keys?", opts: ["6 pairs", "12 pairs", "24 pairs", "3 pairs"], a: 0, fb: "There are 6 tritone substitution pairs: G7↔Db7, D7↔Ab7, A7↔Eb7, E7↔Bb7, B7↔F7, F#7↔C7. Each pair shares the same internal tritone (the guide tones)." },
{ q: "G7 contains the tritone B – F. In Db7, those same notes are...", opts: ["The 9th and the 5th", "The ♭7th (Cb=B) and the 3rd (F)", "The 3rd and the fifth", "The root and the 9th"], a: 1, fb: "In Db7: the 3rd is F and the ♭7th is Cb (Cb = B natural enharmonically). The tritone F–B is shared between G7 and Db7, but the roles are reversed: B (3rd of G7) becomes ♭7 of Db7; F (♭7 of G7) becomes 3rd of Db7." },
{ q: "The 'guide tones' of a chord are...", opts: ["the root and the 5th", "the 3rd and the 7th", "the 9th and the 13th", "the root and the 9th"], a: 1, fb: "Guide tones = 3rd + 7th. These are the notes that define the quality (major/minor) and tension (dominant/Maj7) of a chord. The root and 5th are acoustically redundant; the 3rd and 7th carry all the harmonic information." },
{ q: "In tritone substitution, the guide tones...", opts: ["disappear completely", "remain identical but swap roles (3rd ↔ 7th)", "move by a semitone", "double in octave"], a: 1, fb: "This is the secret of tritone substitution: the two tritone notes remain present, but their roles are reversed. The 3rd of G7 (B) becomes the ♭7th of Db7 (Cb). The ♭7th of G7 (F) becomes the 3rd of Db7 (F). Both chords resolve to C for the same reason: they share the same unstable tritone." },
{ q: "Why do G7 and Db7 both resolve to C major?", opts: ["By historical convention only", "Because they share the same internal tritone (B–F = Cb–F) which resolves to C", "Because they have the same root", "Because they have the same 5th"], a: 1, fb: "G7 and Db7 share the notes B (=Cb) and F — the tritone. This tritone resolves to C and E (B→C ascending semitone, F→E descending semitone). Regardless of whether the bass is G or Db, the guide tones resolve identically to CMaj7." },
{ q: "The resolution of the tritone B–F to C–E involves...", opts: ["B rises a semitone to C; F falls a semitone to E", "B falls to A; F rises to G", "B and F stay in place", "B rises a whole tone to C#; F falls a whole tone to Eb"], a: 0, fb: "B → C (ascending semitone) and F → E (descending semitone). These two semitone movements converge toward the tonic C and its 3rd E. It is this pull of the tritone toward the major third of the tonic that generates tension → resolution." },
{ q: "The standard cadence G7 → C involves what bass movement?", opts: ["Chromatic descent (G→Gb→F→E→...→C)", "Descending fifth (G down to C = descending perfect fifth)", "Ascending fourth", "Stays on G"], a: 1, fb: "G7 → C: the bass descends a perfect fifth (7 semitones) from G to C. This descending fifth movement (or ascending fourth) is the strongest cadential motion in tonal music — the reason why V→I is the archetypal resolution." },
{ q: "The tritone cadence Db7 → C involves what bass movement?", opts: ["Descending fifth (Db → Gb)", "Ascending semitone (Db→D)", "Descending chromatic semitone (Db→C)", "Stays on Db"], a: 2, fb: "Db7 → C: the bass descends a semitone from Db to C. This is the smoothest chromatic movement possible. This sliding resolution (rather than a fifth leap) is the main advantage of tritone substitution: smoothness and chromaticism." },
{ q: "In the standard II-V-I (Dm7–G7–CMaj7), the bass line is...", opts: ["D → Db → C (chromatic)", "D → G → C (descending fifths)", "D → E → C", "D → A → C"], a: 1, fb: "Dm7–G7–CMaj7 in C: bass = D–G–C. D→G = descending fifth (or ascending fourth); G→C = descending fifth. Progression through the cycle of fifths — very strong harmonically, but less smooth linearly." },
{ q: "In the II-V-I with substitution (Dm7–Db7–CMaj7), the bass line is...", opts: ["D → G → C", "D → Db → C (chromatic descent!)", "D → E → C", "D → Ab → C"], a: 1, fb: "With tritone substitution: bass = D–Db–C. This is a chromatic descent of 3 notes (D→Db→C). This bass line is one of the most characteristic features of modern jazz — the pianist or bassist can create this inner voice descending by semitones." },
{ q: "What is the main advantage of the bass line D–Db–C over D–G–C?", opts: ["It is harmonically stronger", "It is more chromatic and smooth — better voice leading", "It avoids all dissonance", "It is easier to sing"], a: 1, fb: "D–Db–C is a chromatic descent of 3 consecutive notes (each note a semitone lower). This linear continuity creates a 'sliding' sensation highly valued in jazz. D–G–C is harmonically stronger but melodically less smooth." },
{ q: "What is the tritone substitution of D7?", opts: ["G7", "Ab7", "Eb7", "A7"], a: 1, fb: "D + 6 semitones = Ab. The tritone substitution of D7 is Ab7. Check: D7 contains F#–C (tritone). Ab7 contains C–Gb/F# (same tritone). ✓" },
{ q: "What is the tritone substitution of A7?", opts: ["Eb7", "D7", "Bb7", "E7"], a: 0, fb: "A + 6 semitones = Eb. The tritone substitution of A7 is Eb7. A7 contains C#–G (tritone). Eb7 contains G–Db (= C#). Same tritone, roles reversed. ✓" },
{ q: "What is the tritone substitution of E7?", opts: ["B7", "Bb7", "A7", "F7"], a: 1, fb: "E + 6 semitones = Bb. The tritone substitution of E7 is Bb7. E7 contains G#–D (tritone). Bb7 contains D–Ab (= G#). ✓" },
{ q: "What is the tritone substitution of C7?", opts: ["F7", "G7", "F#7/Gb7", "Gb7 only"], a: 2, fb: "C + 6 semitones = F# = Gb. The tritone substitution of C7 is F#7 (or Gb7). C7 contains E–Bb (tritone). Gb7 contains Bb–E. Same tritone, inverted. ✓" },
{ q: "What is the tritone substitution of F7?", opts: ["C7", "B7", "Gb7", "Bb7"], a: 1, fb: "F + 6 semitones = B. The tritone substitution of F7 is B7. F7 contains A–Eb (tritone). B7 contains D#–A (= Eb–A). ✓" },
{ q: "What is the tritone substitution of Bb7?", opts: ["Eb7", "F7", "E7", "Ab7"], a: 2, fb: "Bb + 6 semitones = E. The tritone substitution of Bb7 is E7. Bb7 contains D–Ab (tritone). E7 contains G#–D (= Ab–D). ✓" },
{ q: "If the tritone sub of G7 is Db7, what is the tritone sub of Db7?", opts: ["G♭7", "G7", "Ab7", "C7"], a: 1, fb: "The relationship is reciprocal: if Db7 is the tritone sub of G7, then G7 is the tritone sub of Db7. Db + 6 = G. Each tritone substitution pair is symmetrical — you can substitute in both directions." },
{ q: "In Autumn Leaves, the cadence Am7♭5–D7–Gm with substitution becomes...", opts: ["Am7♭5–Ab7–Gm", "Am7♭5–G7–Gm", "Bm7♭5–Ab7–Gm", "Am7♭5–Db7–Gm"], a: 0, fb: "D7 → tritone sub = Ab7 (D + 6 = Ab). Autumn Leaves: Am7♭5–D7–Gm with sub → Am7♭5–Ab7–Gm. The bass line A–Ab–G descends chromatically — very common in jazz arrangements of this standard." },
{ q: "Tritone substitution can be applied to...", opts: ["only the main V7", "any dominant 7th chord (including secondary dominants)", "only major chords", "only in bebop jazz"], a: 1, fb: "Any dominant 7th chord (containing an internal tritone) can be substituted. This includes secondary dominants: V7/II (A7→Eb7), V7/IV (C7→Gb7), etc. That is why tritone substitution is so versatile." },
{ q: "In a II–V–I–IV–VII–III–VI cycle, can all V7 chords be substituted?", opts: ["No — only the main V7", "Yes — every dominant 7th can be replaced by its tritone sub", "Yes, but only the odd-numbered V7s", "No — it would break the tonality"], a: 1, fb: "Yes. In a cycle of dominants (e.g. G7–C7–F7–Bb7 etc.), each chord can be replaced by its tritone sub: Db7–Gb7–B7–E7 etc. This 'chain of substitutions' creates a continuous chromatic descent in the bass — a very modern jazz texture." },
{ q: "The 'Coltrane substitution' in Giant Steps uses...", opts: ["the same shared tritone", "a cycle of major thirds (divides the octave into 3 equal parts)", "only secondary dominants", "diminished chords"], a: 1, fb: "The 'Coltrane changes' of Giant Steps (1960) extend the substitution concept with a cycle of major thirds: B → G → E♭ (each a major third = 4 semitones apart). This is not directly tritone substitution, but a related harmonic development — dividing the octave into 3 equal parts." },
{ q: "In Giant Steps, Coltrane moves through how many different tonal centers in 2 bars?", opts: ["1", "2", "3", "4"], a: 2, fb: "Giant Steps progresses through 3 tonal centers (B, G, E♭) in 2 bars — a harmonic pace unprecedented in 1959. Each center lasts about 2 beats. This is what musicians of the era called 'running the changes' — improvising at extreme harmonic speed." },
{ q: "Which pianist recorded Giant Steps with Coltrane in 1960?", opts: ["Bill Evans", "Herbie Hancock", "Tommy Flanagan", "McCoy Tyner"], a: 2, fb: "Tommy Flanagan played piano on Giant Steps (1960). The story goes that he was so surprised by Coltrane's harmony during the recording that he had to improvise 'from instinct' — his solo is short because he had not yet mastered the Coltrane changes." },
{ q: "Tritone substitution is a technique primarily developed in...", opts: ["Baroque music", "Bebop and modern jazz (1940s–1950s)", "Renaissance music", "Dixieland jazz (1920s)"], a: 1, fb: "Tritone substitution was born in bebop (Charlie Parker, Dizzy Gillespie, Thelonious Monk, 1940s). It was theorized and systematized in the 1950s before being pushed to the extreme by Coltrane in the 1960s." },
{ q: "On Db7 (substitution of G7 → C), what is the major 9th?", opts: ["C", "Eb", "F", "Bb"], a: 1, fb: "9th of Db = major 2nd at the octave = Eb. Db9 = Db–F–Ab–Cb–Eb. The 9th (Eb) is available on Db7 — it resolves to E natural in CMaj7 by ascending semitone. Excellent voice movement!" },
{ q: "On Db7 → C, the 13th of Db7 is...", opts: ["Bb", "Eb", "B", "Ab"], a: 0, fb: "13th of Db = major 6th = Bb. Db13 contains Bb as its 13th. Bb → A (5th of C) = descending semitone — a beautiful resolution. The 13th (Bb) is available on Db7 because it is a whole tone away from Ab (5th of Db7)." },
{ q: "The #11 of Db7 is...", opts: ["G", "G natural", "F#", "Eb"], a: 1, fb: "#11 of Db = augmented 4th = G natural. Db7#11 contains G as its #11. G is the root of G7 — a beautiful harmonic connection between the two substituted chords. Db7#11 → CMaj7 is very common in jazz." },
{ q: "Db7#11 → CMaj7: the #11 (G) resolves to...", opts: ["G (stays in place in CMaj7)", "F (5th of CMaj7)", "E (3rd of CMaj7)", "D (9th of CMaj9)"], a: 0, fb: "G is both the #11 of Db7 and the fifth of CMaj7. The note stays in place during the resolution — it is a 'common tone' that ensures remarkable continuity between the sub and the resolution. A common technique in jazz arrangements." },
{ q: "Tritone substitution preserves which harmonic function?", opts: ["Tonic", "Subdominant", "Dominant (tension → resolution)", "Modal"], a: 2, fb: "Db7 remains a dominant chord — it creates tension (via its internal tritone B–F = Cb–F) that resolves to C. The dominant function is preserved even when the bass changes. This is what makes the substitution harmonically coherent." },
{ q: "The scale degree of Db7 in the key of C major is...", opts: ["♭II7 (flattened second degree)", "IV7", "VI7", "♭VII7"], a: 0, fb: "Db is the flattened second degree of C major (♭II). Db7 used as a tritone substitution for G7 is therefore labeled ♭II7 in functional analysis. This ♭II7→I motion is called a 'Neapolitan resolution' in some analyses — although the jazz mechanism differs from the classical Neapolitan chord." },
{ q: "The tritone substitution of the secondary dominant V7/II (A7) in C is...", opts: ["D7", "Eb7", "E♭7", "Eb7 (= Eb7)"], a: 3, fb: "A7 (dominant of Dm) + 6 semitones = Eb7. The tritone substitution of A7 is Eb7. In a progression Dm7–A7–G7, one can substitute: Dm7–Eb7–G7 or Dm7–Eb7–Db7, creating a chromatic descent Eb→Db→C." },
{ q: "The resolution Db7 → CMaj7 is sometimes compared to the Neapolitan cadence because...", opts: ["both use a chord on ♭II", "both are perfect cadences", "both originate from the Baroque era", "both use the tritone"], a: 0, fb: "The Neapolitan chord (classical ♭II6) and the tritone substitution Db7 share the use of a chord whose root is ♭II (Db in C). The mechanisms differ (classical voice leading vs. jazz tritone), but the ♭II→I function is common to both." },
{ q: "Tritone substitution improves voice leading because...", opts: ["it removes all dissonances", "it creates semitone movements (chromatic voice leading) instead of fifth leaps", "it simplifies the harmony", "it avoids the tritone"], a: 1, fb: "Fifth leaps (G→C) create a strong progression but with large intervals. Tritone substitution (Db→C) replaces the fifth leap with a semitone, improving linearity and smoothness of the voices. This is the chromatic voice leading of jazz." },
{ q: "In the substitution Db7→CMaj7, how many voices move by semitone?", opts: ["1", "2", "3", "0"], a: 2, fb: "3 voices move by semitone: Db→C (bass, ½ step), F→E (3rd of Db7 → 3rd of CMaj7, ½ step), B→C (♭7th of Db7 → root of CMaj7, ascending ½ step). Only Ab (5th of Db7) must leap to G (5th of CMaj7). Exceptional voice leading!" },
{ q: "In the standard resolution G7→CMaj7, how many voices move by semitone?", opts: ["0", "1", "2", "3"], a: 2, fb: "G7→CMaj7: B→C (½ step, leading tone to tonic) and F→E (½ step, ♭7th to 3rd). G (bass) leaps to C (fifth). D can leap to G or C. Two semitone movements — less smooth than the substitution (3 semitones)." },
{ q: "The 'Coltrane changes' divide the octave into...", opts: ["2 equal parts (tritones)", "3 equal parts (major thirds)", "4 equal parts (minor thirds)", "6 equal parts (whole tones)"], a: 1, fb: "Coltrane changes divide the octave into 3 equal parts by major thirds (4 semitones each): B → G → E♭ → B (return). Each major-third division generates a temporary tonal center. This cycle by major thirds is also called the 'Coltrane movement' or 'Coltrane cadence'." },
{ q: "Which John Coltrane album (1960) revolutionized jazz harmony?", opts: ["A Love Supreme", "Kind of Blue", "Giant Steps", "My Favorite Things"], a: 2, fb: "Giant Steps (1960) is the album that introduced the 'Coltrane changes' — a harmonic progression by major thirds at an unprecedented speed. The title track 'Giant Steps' has become one of the most difficult jazz standards to improvise over." },
{ q: "Coltrane's saxophone on 'A Love Supreme' (1964) uses rather...", opts: ["fast Coltrane changes", "a more static modal style over vamps", "systematic tritone substitution", "pentatonic scales only"], a: 1, fb: "A Love Supreme (1964) is more modal — inspired by Miles Davis's Kind of Blue. Coltrane uses long improvisations over modal vamps rather than complex harmonic progressions. It is a balance between his harmonic approach of Giant Steps and modal jazz." },
{ q: "To the ear, Db7→C sounds compared to G7→C...", opts: ["More abrupt and strong", "Smoother and more chromatic — a 'sliding' sensation", "Identical", "More dissonant"], a: 1, fb: "Db7→C sounds smoother because the bass descends by a semitone (Db→C). The resolution seems to 'slide' toward the tonic rather than 'fall' into it (as in G→C by fifth). The result is more surprising and sophisticated — a signature of modern jazz." },
{ q: "The bass Db→C in Db7→C creates an interval of...", opts: ["major second (whole tone)", "minor second (semitone)", "minor third", "fifth"], a: 1, fb: "Db→C = minor second = semitone = 1 semitone. This is the smallest interval in the Western equal-tempered scale. Resolution by descending semitone is the smoothest possible — hence the effect of 'chromatic sliding' so prized in jazz." },
{ q: "The bass G→C in G7→C creates an interval of...", opts: ["perfect fourth (ascending)", "perfect fifth (descending)", "major third", "sixth"], a: 1, fb: "G→C descending = perfect fifth (7 semitones). G→C ascending = perfect fourth. In terms of bass movement, we say 'descending fifth' (G down to C). This is the strongest cadential motion in tonal music." },
{ q: "Can G7 and Db7 be used together in the same bar?", opts: ["No — they are mutually exclusive", "Yes — often as chromatic passing chords (G7–Db7–C)", "Yes, but only in minor mode", "No — they have the same tritone so they sound the same"], a: 1, fb: "G7 and Db7 can coexist as chromatic passing chords: G7–Db7–CMaj7 in a single progression. The bass descends G→Db→C by tritone then semitone. One also sees G7–G♭7–C (♭V7 as a passing chord) in some arrangements." },
{ q: "Is the 'backdoor dominant' (♭VII7→I, e.g. Bb7→C) related to tritone substitution?", opts: ["No — completely different mechanism", "Yes — Bb7 is the tritone sub of E7, not of G7 (related but distinct mechanisms)", "Yes — it is exactly the same thing", "No — the backdoor does not use a tritone"], a: 1, fb: "The backdoor dominant (Bb7→C = ♭VII7→I) uses a chord a whole tone from the tonic, not a tritone. It is a related harmonic mechanism (resolution by step) but distinct from tritone substitution. They do share the idea of resolving to I from a non-conventional chord." },
{ q: "In a blues in A, the cadence IV7–I7 (D7–A7) with substitution becomes...", opts: ["D7–Eb7", "Ab7–A7", "Ab7–Eb7", "D7–Ab7"], a: 3, fb: "D7 (IV7 in A) is not usually substituted in this context. But A7 (I7 in blues) → A + 6 = Eb. Substitution of A7 = Eb7. In the blues, tritone substitution is most often applied to the V7 (E7→A): E7 → Bb7. Bb7→A creates a chromatic resolution by ½ step." },
{ q: "Can tritone substitution be applied to IVMaj7 (major subdominant)?", opts: ["Yes — FMaj7 can be substituted by BMaj7", "No — IVMaj7 has no unstable tritone to resolve", "Yes, but only in jazz fusion", "No — IVMaj7 is always stable"], a: 1, fb: "No. Tritone substitution only applies to dominant 7th chords (containing an unstable tritone). A IVMaj7 chord (FMaj7) has a major 7th — its internal tritone is different and does not carry the same urgency to resolve. The sub concept is tied to dominant tension." },
{ q: "Charlie Parker often used in his improvisations...", opts: ["pentatonic scales only", "substitutions and turnarounds with tritone subs to create chromatic lines", "only the major scale", "stacked quartal chords"], a: 1, fb: "Charlie Parker ('Bird') was a master of harmonic substitutions — he improvised over G7–Db7–C in real time, creating highly chromatic bebop lines. He said: 'If you don't live by the harmony, you'll always be on the outside.' Tritone subs are at the heart of bebop." },
{ q: "Miles Davis in 'Round Midnight' (arrangement) uses substitutions to...", opts: ["simplify Monk's original chords", "enrich Monk's changes with chromatic substitutions", "avoid diminished chords", "transpose the piece to another key"], a: 1, fb: "Miles Davis and Gil Evans enriched 'Round Midnight' (originally by Monk) with many substitutions, notably tritonic ones, creating a denser harmonic texture. This is a perfect example of jazz reharmonization using tritone subs." },
{ q: "The relationship between G7 and Db7 can also be seen as...", opts: ["a distant modulation", "two chords a tritone apart whose guide tone roles are inverted", "two chords sharing the same root", "two chords sharing the same 5th"], a: 1, fb: "G7 and Db7 are a tritone apart (6 semitones) from each other. Their guide tones (B/Cb and F) are exactly the same, with roles reversed (3rd ↔ 7th). This is an elegant harmonic symmetry at the heart of the tritone sub." },
];

const questionsEs: Question[] = [{ q: "Un tritono es un intervalo de...", opts: ["5 semitonos", "6 semitonos", "7 semitonos", "4 semitonos"], a: 1, fb: "El tritono = 6 semitonos = cuarta aumentada = quinta disminuida. Es el intervalo más disonante de la escala temperada — divide la octava (12 semitonos) exactamente en dos. Ej: Do → Fa# = 6 semitonos." },
{ q: "¿Por qué se llama al tritono 'diabolus in musica' en la Edad Media?", opts: ["Era fácil de tocar", "Era el intervalo más consonante", "Su extrema disonancia era considerada peligrosa y estaba prohibida", "Se parecía al sonido de un diablo"], a: 2, fb: "En la Edad Media y el Renacimiento, el tritono estaba explícitamente prohibido en la música de iglesia por su disonancia. 'Diabolus in musica' (diablo en la música) es una expresión que data del tratado de Johannes de Muris (siglo XIV)." },
{ q: "El tritono de Sol es...", opts: ["Ré", "Do#", "Réb", "La"], a: 2, fb: "Sol → Réb = 6 semitonos (Sol=7, Sol#=8, La=9, Sib=10, Si=11, Do=12, Réb=13... partiendo de Do=0: Sol=7, +6=13=Réb en la octava superior... o simplemente: G=7, +6=13=Db modular). Sol + 6 = Réb. Por eso Db7 es la sustitución de tritono de G7." },
{ q: "El tritono de Do es...", opts: ["Sol", "Fa#", "Sib", "La#"], a: 1, fb: "Do → Fa# = 6 semitonos. Do=0, +6=Fa#(Gb). La sustitución de tritono de C7 es F#7 (o Gb7 según el contexto)." },
{ q: "El tritono de Ré es...", opts: ["Sol#", "Lab", "Sol#/Lab (enarmónicos)", "Sol"], a: 2, fb: "Ré + 6 semitonos = Sol# = Lab (notas enarmónicas). Ambas notaciones son equivalentes. La sustitución de tritono de D7 es Ab7." },
{ q: "¿Cuántos pares de sustituciones de tritono existen en las 12 tonalidades?", opts: ["6 pares", "12 pares", "24 pares", "3 pares"], a: 0, fb: "Existen 6 pares de sustituciones de tritono: G7↔Db7, D7↔Ab7, A7↔Eb7, E7↔Bb7, B7↔F7, F#7↔C7. Cada par comparte el mismo tritono interno (las guide tones)." },
{ q: "G7 contiene el tritono B – F. En Db7, esas mismas notas son...", opts: ["La 9na y la 5ta", "La ♭7ma (Cb=B) y la 3ra (F)", "La 3ra y la quinta", "La fundamental y la 9na"], a: 1, fb: "En Db7: la 3ra es Fa (F) y la ♭7ma es Do♭ (Cb = B natural enarmónicamente). El tritono F–B es compartido entre G7 y Db7, pero los roles se invierten: B (3ra de G7) se convierte en ♭7 de Db7; F (♭7 de G7) se convierte en 3ra de Db7." },
{ q: "Las 'guide tones' de un acorde son...", opts: ["la fundamental y la 5ta", "la 3ra y la 7ma", "la 9na y la 13na", "la fundamental y la 9na"], a: 1, fb: "Las guide tones = 3ra + 7ma. Son las notas que definen la calidad (mayor/menor) y la tensión (dominante/Maj7) de un acorde. La fundamental y la 5ta son acústicamente redundantes; la 3ra y la 7ma portan toda la información armónica." },
{ q: "En la sustitución de tritono, las guide tones...", opts: ["desaparecen completamente", "permanecen idénticas pero intercambian sus roles (3ra ↔ 7ma)", "se desplazan un semitono", "se duplican en octava"], a: 1, fb: "Este es el secreto de la sustitución de tritono: las dos notas del tritono permanecen presentes, pero sus roles se invierten. La 3ra de G7 (Si/B) se convierte en la ♭7ma de Db7 (Do♭/Cb). La ♭7ma de G7 (Fa/F) se convierte en la 3ra de Db7 (Fa/F). Ambos acordes resuelven hacia C por la misma razón: comparten el mismo tritono inestable." },
{ q: "¿Por qué G7 y Db7 resuelven ambos hacia Do mayor?", opts: ["Solo por convención histórica", "Porque comparten el mismo tritono interno (B–F = Cb–F) que resuelve hacia C", "Porque tienen la misma fundamental", "Porque tienen la misma 5ta"], a: 1, fb: "G7 y Db7 comparten las notas B (=Cb) y F — el tritono. Este tritono resuelve hacia C y E (B→C semitono ascendente, F→E semitono descendente). Sin importar si el bajo es G o Db, las guide tones resuelven idénticamente hacia CMaj7." },
{ q: "La resolución del tritono B–F hacia C–E implica...", opts: ["B sube un semitono hacia C; F baja un semitono hacia E", "B baja hacia A; F sube hacia G", "B y F se quedan en su lugar", "B sube un tono hacia C#; F baja un tono hacia Eb"], a: 0, fb: "B → C (semitono ascendente) y F → E (semitono descendente). Estos dos movimientos de semitono convergen hacia la tónica C y su 3ra E. Es esta atracción del tritono hacia la tercera mayor de la tónica la que genera la tensión → resolución." },
{ q: "La cadencia estándar G7 → C implica qué movimiento de bajo?", opts: ["Cromático descendente (G→Gb→F→E→...→C)", "Descenso de quinta (G baja a C = descenso de quinta justa)", "Subida de cuarta", "Permanece en G"], a: 1, fb: "G7 → C: el bajo desciende una quinta justa (7 semitonos) de Sol a Do. Este movimiento de quinta descendente (o subida de cuarta) es el movimiento cadencial más fuerte de la tonalidad — la razón por la que V→I es la resolución arquetípica." },
{ q: "La cadencia de tritono Db7 → C implica qué movimiento de bajo?", opts: ["Descenso de quinta (Db → Gb)", "Subida de un semitono (Db→D)", "Descenso cromático de un semitono (Db→C)", "Permanece en Db"], a: 2, fb: "Db7 → C: el bajo desciende un semitono de Réb a Do. Es el movimiento cromático más suave posible. Esta resolución por deslizamiento (en lugar del salto de quinta) es la principal ventaja de la sustitución de tritono: suavidad y cromatismo." },
{ q: "En el II-V-I estándar (Dm7–G7–CMaj7), la línea de bajo es...", opts: ["D → Db → C (cromática)", "D → G → C (quintas descendentes)", "D → E → C", "D → A → C"], a: 1, fb: "Dm7–G7–CMaj7 en Do: bajo = Ré–Sol–Do. Ré→Sol = quinta descendente (o cuarta ascendente); Sol→Do = quinta descendente. Progresión por ciclo de quintas — muy fuerte armónicamente, menos suave linealmente." },
{ q: "En el II-V-I con sustitución (Dm7–Db7–CMaj7), la línea de bajo es...", opts: ["D → G → C", "D → Db → C (¡descenso cromático!)", "D → E → C", "D → Ab → C"], a: 1, fb: "Con la sustitución de tritono: bajo = Ré–Réb–Do. Es un descenso cromático de 3 notas (D→Db→C). Esta línea de bajo es uno de los efectos más característicos del jazz moderno — el pianista o el bajista puede crear esta voz interior que desciende por semitonos." },
{ q: "¿Cuál es la principal ventaja de la línea de bajo D–Db–C frente a D–G–C?", opts: ["Es armónicamente más fuerte", "Es más cromática y suave — mejor conducción de voces", "Evita toda disonancia", "Es más fácil de cantar"], a: 1, fb: "D–Db–C es un descenso cromático de 3 notas consecutivas (cada nota es un semitono más bajo). Esta continuidad lineal crea una sensación de 'deslizamiento' muy apreciada en el jazz. D–G–C es más fuerte armónicamente pero menos suave melódicamente." },
{ q: "¿Cuál es la sustitución de tritono de D7?", opts: ["G7", "Ab7", "Eb7", "A7"], a: 1, fb: "Ré + 6 semitonos = Lab = Ab. La sustitución de tritono de D7 es Ab7. Verificación: D7 contiene F#–C (tritono). Ab7 contiene C–Gb/F# (mismo tritono). ✓" },
{ q: "¿Cuál es la sustitución de tritono de A7?", opts: ["Eb7", "D7", "Bb7", "E7"], a: 0, fb: "La + 6 semitonos = Mi♭ = Eb. La sustitución de tritono de A7 es Eb7. A7 contiene C#–G (tritono). Eb7 contiene G–Db (= C#). Mismo tritono, roles invertidos. ✓" },
{ q: "¿Cuál es la sustitución de tritono de E7?", opts: ["B7", "Bb7", "A7", "F7"], a: 1, fb: "Mi + 6 semitonos = Si♭ = Bb. La sustitución de tritono de E7 es Bb7. E7 contiene G#–D (tritono). Bb7 contiene D–Ab (= G#). ✓" },
{ q: "¿Cuál es la sustitución de tritono de C7?", opts: ["F7", "G7", "F#7/Gb7", "Gb7 únicamente"], a: 2, fb: "Do + 6 semitonos = Fa# = Gb. La sustitución de tritono de C7 es F#7 (o Gb7). C7 contiene E–Bb (tritono). Gb7 contiene Bb–E. Mismo tritono invertido. ✓" },
{ q: "¿Cuál es la sustitución de tritono de F7?", opts: ["C7", "B7", "Gb7", "Bb7"], a: 1, fb: "Fa + 6 semitonos = Si = B. La sustitución de tritono de F7 es B7. F7 contiene A–Eb (tritono). B7 contiene D#–A (= Eb–A). ✓" },
{ q: "¿Cuál es la sustitución de tritono de Bb7?", opts: ["Eb7", "F7", "E7", "Ab7"], a: 2, fb: "Si♭ + 6 semitonos = Mi = E. La sustitución de tritono de Bb7 es E7. Bb7 contiene D–Ab (tritono). E7 contiene G#–D (= Ab–D). ✓" },
{ q: "Si el tritono sub de G7 es Db7, ¿cuál es el tritono sub de Db7?", opts: ["G♭7", "G7", "Ab7", "C7"], a: 1, fb: "La relación es recíproca: si Db7 es el tritono sub de G7, entonces G7 es el tritono sub de Db7. Réb + 6 = Sol. Cada par de sustituciones de tritono es simétrico — se puede sustituir en ambos sentidos." },
{ q: "En Autumn Leaves, la cadencia Am7♭5–D7–Gm con sustitución se convierte en...", opts: ["Am7♭5–Ab7–Gm", "Am7♭5–G7–Gm", "Bm7♭5–Ab7–Gm", "Am7♭5–Db7–Gm"], a: 0, fb: "D7 → sub de tritono = Ab7 (Ré + 6 = Lab). Autumn Leaves: Am7♭5–D7–Gm con sub → Am7♭5–Ab7–Gm. La línea de bajo A–Ab–G desciende cromáticamente — muy común en los arreglos jazz de este estándar." },
{ q: "La sustitución de tritono puede aplicarse a...", opts: ["únicamente el V7 principal", "cualquier acorde de dominante de 7ma (incluidas las dominantes secundarias)", "únicamente los acordes mayores", "únicamente en jazz bebop"], a: 1, fb: "Todo acorde dominante de 7ma (que contenga un tritono interno) puede ser sustituido. Esto incluye las dominantes secundarias: V7/II (A7→Eb7), V7/IV (C7→Gb7), etc. Por eso la sustitución de tritono es tan versátil." },
{ q: "En un ciclo II–V–I–IV–VII–III–VI, ¿se pueden sustituir todos los V7?", opts: ["No — únicamente el V7 principal", "Sí — cada dominante de 7ma puede reemplazarse por su tritono sub", "Sí, pero solo los V7 impares", "No — eso rompería la tonalidad"], a: 1, fb: "Sí. En un ciclo de dominantes (ej: G7–C7–F7–Bb7 etc.), cada acorde puede reemplazarse por su tritono sub: Db7–Gb7–B7–E7 etc. Esta 'cadena de sustituciones' crea un descenso cromático continuo en el bajo — textura muy característica del jazz moderno." },
{ q: "La 'sustitución de Coltrane' en Giant Steps utiliza...", opts: ["el mismo tritono compartido", "un ciclo de terceras mayores (divide la octava en 3 partes iguales)", "únicamente dominantes secundarias", "acordes disminuidos"], a: 1, fb: "Los 'Coltrane changes' de Giant Steps (1960) extienden el concepto de sustitución con un ciclo de terceras mayores: B → G → E♭ (cada uno a distancia de tercera mayor = 4 semitonos). No es directamente la sustitución de tritono, sino un desarrollo armónico relacionado — dividir la octava en 3 partes iguales." },
{ q: "En Giant Steps, Coltrane pasa por cuántos centros tonales diferentes en 2 compases?", opts: ["1", "2", "3", "4"], a: 2, fb: "Giant Steps progresa por 3 centros tonales (B, G, E♭) en 2 compases — un movimiento armónico a una velocidad inaudita para 1959. Cada centro dura aproximadamente 2 tiempos. Esto es lo que los músicos de la época llamaban 'correr los cambios' — había que improvisar a una velocidad armónica extrema." },
{ q: "¿Qué pianista grabó Giant Steps con Coltrane en 1960?", opts: ["Bill Evans", "Herbie Hancock", "Tommy Flanagan", "McCoy Tyner"], a: 2, fb: "Tommy Flanagan tocó el piano en Giant Steps (1960). La historia cuenta que quedó tan sorprendido por la armonía de Coltrane durante la grabación que tuvo que improvisar 'de memoria' — su solo es breve porque aún no dominaba los Coltrane changes." },
{ q: "La sustitución de tritono es una técnica desarrollada principalmente en...", opts: ["la música barroca", "el bebop y el jazz moderno (años 1940-1950)", "la música del Renacimiento", "el jazz dixieland (años 1920)"], a: 1, fb: "La sustitución de tritono nació en el bebop (Charlie Parker, Dizzy Gillespie, Thelonious Monk, años 1940). Fue teorizada y sistematizada en los años 1950 antes de ser llevada al extremo por Coltrane en los años 1960." },
{ q: "Sobre Db7 (sustitución de G7 → C), ¿cuál es la 9na mayor?", opts: ["Do", "Mi♭", "Fa", "Si♭"], a: 1, fb: "9na de Réb = 2da mayor en la octava = Mi♭. Db9 = Réb–Fa–Lab–Do♭–Mi♭. La 9na (Mi♭) está disponible en Db7 — resuelve hacia Mi natural en CMaj7 por semitono ascendente. ¡Excelente movimiento de voces!" },
{ q: "Sobre Db7 → C, la 13na de Db7 es...", opts: ["Si♭", "Mi♭", "Si", "La♭"], a: 0, fb: "13na de Réb = 6ta mayor = Si♭. Db13 contiene Si♭ como 13na. Si♭ → La (5ta de C) = semitono descendente — bella resolución. La 13na (Bb/Si♭) está disponible en Db7 porque se encuentra a distancia de tono de Lab (5ta de Db7)." },
{ q: "La #11 de Db7 es...", opts: ["Sol", "Sol natural (G)", "Fa#", "Mi♭"], a: 1, fb: "#11 de Réb = cuarta aumentada = Sol natural (G). Db7#11 contiene Sol como #11. Sol es la fundamental de G7 — es una bella conexión armónica entre los dos acordes sustituidos. Db7#11 → CMaj7 es muy común en jazz." },
{ q: "Db7#11 → CMaj7: la #11 (Sol) resuelve hacia...", opts: ["Sol (permanece en CMaj7)", "Fa (5ta de CMaj7)", "Mi (3ra de CMaj7)", "Ré (9na de CMaj9)"], a: 0, fb: "Sol es a la vez la #11 de Db7 y la quinta de CMaj7. La nota permanece en su lugar durante la resolución — es una 'common tone' (nota común) que asegura una continuidad notable entre el sub y la resolución. Técnica habitual en los arreglos jazz." },
{ q: "La sustitución de tritono preserva qué función armónica?", opts: ["Tónica", "Subdominante", "Dominante (tensión → resolución)", "Modal"], a: 2, fb: "Db7 sigue siendo un acorde de dominante — crea tensión (a través de su tritono interno B–F = Cb–F) que resuelve hacia C. La función dominante se preserva aunque el bajo cambie. Eso es lo que hace que la sustitución sea armónicamente coherente." },
{ q: "El grado de Db7 en la escala de Do mayor es...", opts: ["♭II7 (segundo grado bemolizado)", "IV7", "VI7", "♭VII7"], a: 0, fb: "Réb es el II grado bemolizado de Do mayor (♭II). Db7 utilizado como sustitución de tritono de G7 se escribe ♭II7 en el análisis funcional. Este movimiento ♭II7→I se denomina 'resolución napolitana' en algunos análisis — aunque el mecanismo jazz difiere del acorde napolitano clásico." },
{ q: "La sustitución de tritono de la dominante secundaria V7/II (A7) en Do es...", opts: ["D7", "Eb7", "E♭7", "Eb7 (= Mi♭7)"], a: 3, fb: "A7 (dominante de Dm) + 6 semitonos = Eb7. La sustitución de tritono de A7 es Eb7. En una progresión Dm7–A7–G7, se puede sustituir: Dm7–Eb7–G7 o Dm7–Eb7–Db7, creando un descenso cromático Mi♭→Ré♭→Do." },
{ q: "La resolución Db7 → CMaj7 a veces se compara con la cadencia napolitana porque...", opts: ["ambas utilizan un acorde sobre ♭II", "ambas son cadencias perfectas", "ambas provienen del barroco", "ambas utilizan el tritono"], a: 0, fb: "El acorde napolitano (♭II6 clásico) y la sustitución de tritono Db7 comparten el uso de un acorde cuya fundamental es ♭II (Réb en Do). Los mecanismos difieren (conducción de voces clásica vs tritono jazz), pero la función ♭II→I es común." },
{ q: "La sustitución de tritono mejora la conducción de voces porque...", opts: ["elimina todas las disonancias", "crea movimientos por semitonos (conducción cromática) en lugar de saltos de quinta", "simplifica la armonía", "evita el tritono"], a: 1, fb: "Los saltos de quinta (G→C) crean una progresión fuerte pero con grandes intervalos. La sustitución de tritono (Db→C) reemplaza el salto de quinta por un semitono, mejorando la linealidad y la fluidez de las voces. Es la conducción cromática de voces (chromatic voice leading) del jazz." },
{ q: "En la sustitución Db7→CMaj7, ¿cuántas voces se mueven por semitono?", opts: ["1", "2", "3", "0"], a: 2, fb: "3 voces se mueven por semitono: Réb→Do (bajo, ½ tono), Fa→Mi (3ra de Db7 → 3ra de CMaj7, ½ tono), Si→Do (♭7ma de Db7 → fundamental de CMaj7, ½ tono ascendente). Solo Lab (5ta de Db7) debe saltar hacia Sol (quinta de CMaj7). ¡Conducción de voces excepcional!" },
{ q: "En la resolución G7→CMaj7 (estándar), ¿cuántas voces se mueven por semitono?", opts: ["0", "1", "2", "3"], a: 2, fb: "G7→CMaj7: Si→Do (½ tono, sensible hacia tónica) y Fa→Mi (½ tono, ♭7ma hacia 3ra). Sol (bajo) salta a Do (quinta). Ré puede saltar hacia Sol o Do. Dos movimientos por semitono — menos suave que la sustitución (3 semitonos)." },
{ q: "Los 'Coltrane changes' dividen la octava en...", opts: ["2 partes iguales (tritonos)", "3 partes iguales (terceras mayores)", "4 partes iguales (terceras menores)", "6 partes iguales (tonos enteros)"], a: 1, fb: "Los Coltrane changes dividen la octava en 3 partes iguales por terceras mayores (4 semitonos cada una): B → G → E♭ → B (regreso). Cada división de tercera mayor genera un centro tonal temporal. Este ciclo por terceras mayores también se llama 'movimiento de Coltrane' o 'cadencia de Coltrane'." },
{ q: "¿Qué álbum de John Coltrane (1960) revolucionó la armonía jazz?", opts: ["A Love Supreme", "Kind of Blue", "Giant Steps", "My Favorite Things"], a: 2, fb: "Giant Steps (1960) es el álbum que introdujo los 'Coltrane changes' — una progresión armónica por terceras mayores a una velocidad inaudita. El tema titular 'Giant Steps' se convirtió en uno de los estándares jazz más difíciles de improvisar." },
{ q: "El saxofón de Coltrane en 'A Love Supreme' (1964) usa más bien...", opts: ["Coltrane changes rápidos", "un estilo modal más estático sobre vamps", "la sustitución de tritono sistemática", "únicamente escalas pentatónicas"], a: 1, fb: "A Love Supreme (1964) es más modal — inspirado en Kind of Blue de Miles Davis. Coltrane usa aquí largas improvisaciones sobre vamps modales en lugar de progresiones armónicas complejas. Es un equilibrio entre su enfoque armónico de Giant Steps y el jazz modal." },
{ q: "Al oído, Db7→C suena en comparación con G7→C...", opts: ["Más abrupto y fuerte", "Más suave y cromático — sensación de 'deslizamiento'", "Idéntico", "Más disonante"], a: 1, fb: "Db7→C suena más suave porque el bajo desciende por semitono (Réb→Do). La resolución parece 'deslizarse' hacia la tónica en lugar de 'caer' sobre ella (como en G→C por quinta). El resultado es más sorprendente y sofisticado — sello del jazz moderno." },
{ q: "El bajo Réb→Do en Db7→C crea un intervalo de...", opts: ["segunda mayor (tono)", "segunda menor (semitono)", "tercera menor", "quinta"], a: 1, fb: "Réb→Do = segunda menor = semitono = 1 semitono. Es el intervalo más pequeño de la escala temperada occidental. La resolución por semitono descendente es la más suave posible — de ahí el efecto de 'deslizamiento cromático' tan buscado en jazz." },
{ q: "El bajo Sol→Do en G7→C crea un intervalo de...", opts: ["cuarta justa (ascendente)", "quinta justa (descendente)", "tercera mayor", "sexta"], a: 1, fb: "Sol→Do descendente = quinta justa (7 semitonos). Sol→Do ascendente = cuarta justa. En términos de movimiento de bajo, se dice 'descenso de quinta' (G down to C). Es el movimiento cadencial más fuerte de la tonalidad." },
{ q: "¿Pueden oírse G7 y Db7 utilizados juntos en el mismo compás?", opts: ["No — se excluyen mutuamente", "Sí — a menudo como acordes de paso cromáticos (G7–Db7–C)", "Sí, pero únicamente en modo menor", "No — tienen el mismo tritono y suenan igual"], a: 1, fb: "G7 y Db7 pueden coexistir como acordes de paso cromáticos: G7–Db7–CMaj7 en una sola progresión. El bajo desciende G→Db→C por tritono y luego semitono. También se ve G7–G♭7–C (♭V7 como passing chord) en ciertos arreglos." },
{ q: "El 'backdoor dominant' (♭VII7→I, ej: Bb7→C), ¿está relacionado con la sustitución de tritono?", opts: ["No — mecanismo completamente diferente", "Sí — Bb7 es el tritono sub de E7, no de G7 (mecanismos relacionados pero distintos)", "Sí — es exactamente lo mismo", "No — el backdoor no utiliza tritono"], a: 1, fb: "El backdoor dominant (Bb7→C = ♭VII7→I) utiliza un acorde a distancia de tono de la tónica, no de tritono. Es un mecanismo armónico relacionado (resolución por deslizamiento) pero distinto de la sustitución de tritono. Comparten, sin embargo, la idea de resolver hacia I desde un acorde no convencional." },
{ q: "En un blues en La, la cadencia IV7–I7 (D7–A7) con sustitución se convierte en...", opts: ["D7–Eb7", "Ab7–A7", "Ab7–Eb7", "D7–Ab7"], a: 3, fb: "D7 (IV7 en La) no se sustituye habitualmente en este contexto. Pero A7 (I7 en blues) → La + 6 = Mi♭. Sustitución de A7 = Eb7. En el blues, la sustitución de tritono se aplica sobre todo a los V7 (E7→La): E7 → Bb7. Bb7→A crea una resolución cromática por ½ tono." },
{ q: "¿Puede aplicarse la sustitución de tritono al IVMaj7 (subdominante mayor)?", opts: ["Sí — FMaj7 puede sustituirse por BMaj7", "No — el IVMaj7 no tiene un tritono inestable que resolver", "Sí, pero solo en jazz fusión", "No — el IVMaj7 siempre es estable"], a: 1, fb: "No. La sustitución de tritono solo se aplica a los acordes de dominante de 7ma (que contienen un tritono inestable). Un acorde IVMaj7 (FMaj7) tiene una 7ma mayor — su tritono interno es diferente y no tiene la misma urgencia de resolución. El concepto de sub está ligado a la tensión dominante." },
{ q: "Charlie Parker utilizaba a menudo en sus improvisaciones...", opts: ["únicamente escalas pentatónicas", "'sustituciones' y 'turnarounds' con tritono subs para crear líneas cromáticas", "únicamente la escala mayor", "acordes de cuartas apiladas"], a: 1, fb: "Charlie Parker ('Bird') era un maestro de las sustituciones armónicas — improvisaba sobre G7–Db7–C en tiempo real, creando líneas bebop muy cromáticas. Dijo: 'Si no vives en la armonía, siempre estarás fuera.' Los tritono subs están en el corazón del bebop." },
{ q: "Miles Davis en 'Round Midnight' (arreglo) usa las sustituciones para...", opts: ["simplificar los acordes originales de Monk", "enriquecer los cambios de Monk con sustituciones cromaticas", "evitar los acordes disminuidos", "transportar la pieza a otra tonalidad"], a: 1, fb: "Miles Davis y Gil Evans enriquecieron 'Round Midnight' (originalmente de Monk) con numerosas sustituciones, notablemente tritono subs, creando una textura armónica más densa. Es un ejemplo perfecto de rearmonización jazz." },
  { q: "La relación entre G7 y Db7 también puede verse como...", opts: ["una modulación distante", "dos acordes a distancia de tritono cuyos roles de notas guía se invierten", "dos acordes con la misma fundamental", "dos acordes con la misma 5ª"], a: 1, fb: "G7 y Db7 están a distancia de tritono (6 semitonos) el uno del otro. Sus guide tones (Si/Do♭ y Fa) son exactamente los mismos, con los roles invertidos (3ª ↔ 7ª). Es una simetría armónica elegante en el corazón del tritono sub." },
];

const questionsDe: Question[] = [{ q: "Ein Tritonus ist ein Intervall von...", opts: ["5 Halbtönen", "6 Halbtönen", "7 Halbtönen", "4 Halbtönen"], a: 1, fb: "Der Tritonus = 6 Halbtöne = übermäßige Quarte = verminderte Quinte. Er ist das dissonanteste Intervall der temperierten Stimmung — er teilt die Oktave (12 Halbtöne) genau in zwei Hälften. Bsp.: C → F# = 6 Halbtöne." },
{ q: "Warum wird der Tritonus im Mittelalter 'diabolus in musica' genannt?", opts: ["Er war leicht zu spielen", "Er war das konsonanteste Intervall", "Seine extreme Dissonanz galt als gefährlich und war verboten", "Er klang wie ein Teufel"], a: 2, fb: "Im Mittelalter und in der Renaissance war der Tritonus in der Kirchenmusik ausdrücklich verboten — aufgrund seiner Dissonanz. 'Diabolus in musica' (Teufel in der Musik) ist ein Ausdruck, der auf den Traktat von Johannes de Muris (14. Jahrhundert) zurückgeht." },
{ q: "Der Tritonus von G ist...", opts: ["D", "C#", "Db", "A"], a: 2, fb: "G → Db = 6 Halbtöne. G + 6 = Db. Deshalb ist Db7 die Tritonussubstitution von G7." },
{ q: "Der Tritonus von C ist...", opts: ["G", "F#", "Bb", "A#"], a: 1, fb: "C → F# = 6 Halbtöne. C = 0, +6 = F# (Gb). Die Tritonussubstitution von C7 ist F#7 (oder Gb7, je nach Kontext)." },
{ q: "Der Tritonus von D ist...", opts: ["G#", "Ab", "G#/Ab (enharmonisch)", "G"], a: 2, fb: "D + 6 Halbtöne = G# = Ab (enharmonische Töne). Beide Schreibweisen sind gleichwertig. Die Tritonussubstitution von D7 ist Ab7." },
{ q: "Wie viele Tritonussubstitutions-Paare gibt es in den 12 Tonarten?", opts: ["6 Paare", "12 Paare", "24 Paare", "3 Paare"], a: 0, fb: "Es gibt 6 Tritonussubstitutions-Paare: G7↔Db7, D7↔Ab7, A7↔Eb7, E7↔Bb7, B7↔F7, F#7↔C7. Jedes Paar teilt denselben internen Tritonus (die Guide Tones)." },
{ q: "G7 enthält den Tritonus B – F. In Db7 sind diese Noten...", opts: ["Die None und die Quinte", "Die ♭7 (Cb=B) und die Terz (F)", "Die Terz und die Quinte", "Der Grundton und die None"], a: 1, fb: "In Db7: die Terz ist F und die ♭7 ist Cb (= B enharmonisch). Der Tritonus F–B wird zwischen G7 und Db7 geteilt, aber die Rollen kehren sich um: B (Terz von G7) wird zur ♭7 von Db7; F (♭7 von G7) wird zur Terz von Db7." },
{ q: "Die 'Guide Tones' eines Akkords sind...", opts: ["Grundton und Quinte", "Terz und Septime", "None und Tredezime", "Grundton und None"], a: 1, fb: "Guide Tones = Terz + Septime. Das sind die Töne, die die Qualität (dur/moll) und die Spannung (dominant/Maj7) eines Akkords bestimmen. Grundton und Quinte sind akustisch redundant; Terz und Septime tragen die gesamte harmonische Information." },
{ q: "Bei der Tritonussubstitution...", opts: ["verschwinden die Guide Tones vollständig", "bleiben die Guide Tones identisch, tauschen aber ihre Rollen (Terz ↔ Septime)", "verschieben sie sich um einen Halbton", "verdoppeln sie sich in der Oktave"], a: 1, fb: "Das ist das Geheimnis der Tritonussubstitution: die beiden Tritonustöne bleiben erhalten, aber ihre Rollen kehren sich um. Die Terz von G7 (B) wird zur ♭7 von Db7 (Cb). Die ♭7 von G7 (F) wird zur Terz von Db7 (F). Beide Akkorde lösen sich nach C auf, weil sie denselben instabilen Tritonus teilen." },
{ q: "Warum lösen sich G7 und Db7 beide nach C-Dur auf?", opts: ["Ausschließlich aus historischer Konvention", "Weil sie denselben internen Tritonus (B–F = Cb–F) teilen, der sich nach C auflöst", "Weil sie denselben Grundton haben", "Weil sie dieselbe Quinte haben"], a: 1, fb: "G7 und Db7 teilen die Töne B (=Cb) und F — den Tritonus. Dieser Tritonus löst sich nach C und E auf (B→C Halbton aufwärts, F→E Halbton abwärts). Unabhängig davon, ob der Bass G oder Db ist, lösen sich die Guide Tones identisch nach CMaj7 auf." },
{ q: "Die Auflösung des Tritonus B–F nach C–E bedeutet...", opts: ["B steigt einen Halbton zu C; F fällt einen Halbton zu E", "B fällt zu A; F steigt zu G", "B und F bleiben liegen", "B steigt einen Ganzton zu C#; F fällt einen Ganzton zu Eb"], a: 0, fb: "B → C (Halbton aufwärts) und F → E (Halbton abwärts). Diese beiden Halbtonbewegungen konvergieren zur Tonika C und ihrer Terz E. Es ist diese Anziehungskraft des Tritonus zur großen Terz der Tonika, die die Spannung → Auflösung erzeugt." },
{ q: "Die Standardkadenz G7 → C beinhaltet welche Bassbewegung?", opts: ["Chromatisch absteigend (G→Gb→F→E→...→C)", "Quintfall (G nach C = reine Quinte abwärts)", "Quartanstieg", "Bleibt auf G"], a: 1, fb: "G7 → C: der Bass fällt eine reine Quinte (7 Halbtöne) von G nach C. Diese absteigende Quintbewegung (oder aufsteigende Quarte) ist die stärkste Kadenzbewegung der Tonalität — der Grund, warum V→I die archetypische Auflösung ist." },
{ q: "Die Tritonuskadenz Db7 → C beinhaltet welche Bassbewegung?", opts: ["Quintfall (Db → Gb)", "Halbtonanstieg (Db→D)", "Chromatischer Halbtonfall (Db→C)", "Bleibt auf Db"], a: 2, fb: "Db7 → C: der Bass fällt einen Halbton von Db nach C. Das ist die glattestmögliche chromatische Bewegung. Diese Auflösung durch Gleiten (statt Quintsprung) ist der Hauptvorteil der Tritonussubstitution: Weichheit und Chromatik." },
{ q: "Im Standard-II-V-I (Dm7–G7–CMaj7) ist die Basslinie...", opts: ["D → Db → C (chromatisch)", "D → G → C (absteigende Quinten)", "D → E → C", "D → A → C"], a: 1, fb: "Dm7–G7–CMaj7 in C: Bass = D–G–C. D→G = absteigende Quinte (oder aufsteigende Quarte); G→C = absteigende Quinte. Progression im Quintenzirkel — harmonisch sehr stark, linear weniger glatt." },
{ q: "Im II-V-I mit Substitution (Dm7–Db7–CMaj7) ist die Basslinie...", opts: ["D → G → C", "D → Db → C (chromatischer Abstieg!)", "D → E → C", "D → Ab → C"], a: 1, fb: "Mit der Tritonussubstitution: Bass = D–Db–C. Das ist ein chromatischer Abstieg mit 3 Tönen (D→Db→C). Diese Basslinie ist eine der charakteristischsten Wirkungen des modernen Jazz — der Pianist oder Bassist kann diese innere Stimme erzeugen, die sich in Halbtönen abwärts bewegt." },
{ q: "Was ist der Hauptvorteil der Basslinie D–Db–C gegenüber D–G–C?", opts: ["Sie ist harmonisch stärker", "Sie ist chromatischer und glatter — bessere Stimmführung", "Sie vermeidet jede Dissonanz", "Sie ist leichter zu singen"], a: 1, fb: "D–Db–C ist ein chromatischer Abstieg mit 3 aufeinanderfolgenden Tönen (jede Note einen Halbton tiefer). Diese lineare Kontinuität erzeugt ein sehr geschätztes 'Gleiten' im Jazz. D–G–C ist harmonisch stärker, aber melodisch weniger glatt." },
{ q: "Was ist die Tritonussubstitution von D7?", opts: ["G7", "Ab7", "Eb7", "A7"], a: 1, fb: "D + 6 Halbtöne = Ab. Die Tritonussubstitution von D7 ist Ab7. Überprüfung: D7 enthält F#–C (Tritonus). Ab7 enthält C–Gb/F# (derselbe Tritonus). ✓" },
{ q: "Was ist die Tritonussubstitution von A7?", opts: ["Eb7", "D7", "Bb7", "E7"], a: 0, fb: "A + 6 Halbtöne = Eb. Die Tritonussubstitution von A7 ist Eb7. A7 enthält C#–G (Tritonus). Eb7 enthält G–Db (= C#). Derselbe Tritonus, Rollen vertauscht. ✓" },
{ q: "Was ist die Tritonussubstitution von E7?", opts: ["B7", "Bb7", "A7", "F7"], a: 1, fb: "E + 6 Halbtöne = Bb. Die Tritonussubstitution von E7 ist Bb7. E7 enthält G#–D (Tritonus). Bb7 enthält D–Ab (= G#). ✓" },
{ q: "Was ist die Tritonussubstitution von C7?", opts: ["F7", "G7", "F#7/Gb7", "Gb7 ausschließlich"], a: 2, fb: "C + 6 Halbtöne = F# = Gb. Die Tritonussubstitution von C7 ist F#7 (oder Gb7). C7 enthält E–Bb (Tritonus). Gb7 enthält Bb–E. Derselbe Tritonus, umgekehrt. ✓" },
{ q: "Was ist die Tritonussubstitution von F7?", opts: ["C7", "B7", "Gb7", "Bb7"], a: 1, fb: "F + 6 Halbtöne = B. Die Tritonussubstitution von F7 ist B7. F7 enthält A–Eb (Tritonus). B7 enthält D#–A (= Eb–A). ✓" },
{ q: "Was ist die Tritonussubstitution von Bb7?", opts: ["Eb7", "F7", "E7", "Ab7"], a: 2, fb: "Bb + 6 Halbtöne = E. Die Tritonussubstitution von Bb7 ist E7. Bb7 enthält D–Ab (Tritonus). E7 enthält G#–D (= Ab–D). ✓" },
{ q: "Wenn der Tritonus-Sub von G7 Db7 ist, was ist dann der Tritonus-Sub von Db7?", opts: ["Gb7", "G7", "Ab7", "C7"], a: 1, fb: "Die Beziehung ist reziprok: wenn Db7 der Tritonus-Sub von G7 ist, dann ist G7 der Tritonus-Sub von Db7. Db + 6 = G. Jedes Tritonussubstitutions-Paar ist symmetrisch — man kann in beide Richtungen substituieren." },
{ q: "In Autumn Leaves wird die Kadenz Am7♭5–D7–Gm mit Substitution zu...", opts: ["Am7♭5–Ab7–Gm", "Am7♭5–G7–Gm", "Bm7♭5–Ab7–Gm", "Am7♭5–Db7–Gm"], a: 0, fb: "D7 → Tritonus-Sub = Ab7 (D + 6 = Ab). Autumn Leaves: Am7♭5–D7–Gm mit Sub → Am7♭5–Ab7–Gm. Die Basslinie A–Ab–G steigt chromatisch ab — sehr verbreitet in Jazz-Arrangements dieses Standards." },
{ q: "Die Tritonussubstitution kann angewendet werden auf...", opts: ["ausschließlich den Haupt-V7", "jeden Dominant-Septakkord (einschließlich Sekundärdominanten)", "ausschließlich Durakkorde", "ausschließlich im Bebop-Jazz"], a: 1, fb: "Jeder Dominant-Septakkord (mit internem Tritonus) kann substituiert werden. Das schließt Sekundärdominanten ein: V7/II (A7→Eb7), V7/IV (C7→Gb7) usw. Deshalb ist die Tritonussubstitution so vielseitig." },
{ q: "In einem Zyklus II–V–I–IV–VII–III–VI, kann man alle V7 substituieren?", opts: ["Nein — nur den Haupt-V7", "Ja — jeder Dominant-Septakkord kann durch seinen Tritonus-Sub ersetzt werden", "Ja, aber nur die ungeraden V7", "Nein — das würde die Tonalität zerstören"], a: 1, fb: "Ja. In einem Dominantenzyklus (z.B. G7–C7–F7–Bb7 usw.) kann jeder Akkord durch seinen Tritonus-Sub ersetzt werden: Db7–Gb7–B7–E7 usw. Diese 'Substitutionskette' erzeugt einen kontinuierlichen chromatischen Abstieg im Bass — sehr moderner Jazz-Sound." },
{ q: "Die 'Coltrane-Substitution' in Giant Steps verwendet...", opts: ["denselben geteilten Tritonus", "einen Terzzirkel (teilt die Oktave in 3 gleiche Teile)", "ausschließlich Sekundärdominanten", "verminderte Akkorde"], a: 1, fb: "Die 'Coltrane Changes' aus Giant Steps (1960) erweitern das Substitutionskonzept durch einen Großterzzirkel: B → G → Eb (jeweils eine große Terz = 4 Halbtöne entfernt). Das ist nicht direkt die Tritonussubstitution, sondern eine verwandte harmonische Entwicklung — die Oktave in 3 gleiche Teile teilen." },
{ q: "In Giant Steps wechselt Coltrane in 2 Takten durch wie viele verschiedene Tonzentren?", opts: ["1", "2", "3", "4"], a: 2, fb: "Giant Steps bewegt sich durch 3 Tonzentren (B, G, Eb) in 2 Takten — eine für 1959 unerhörte harmonische Geschwindigkeit. Jedes Zentrum dauert etwa 2 Zählzeiten. Das nannten die Musiker damals 'die Wechsel jagen' — man musste bei extremer harmonischer Geschwindigkeit improvisieren." },
{ q: "Welcher Pianist nahm Giant Steps 1960 mit Coltrane auf?", opts: ["Bill Evans", "Herbie Hancock", "Tommy Flanagan", "McCoy Tyner"], a: 2, fb: "Tommy Flanagan spielte Klavier auf Giant Steps (1960). Der Legende nach war er bei der Aufnahme so überrascht von Coltranes Harmonik, dass er 'aus dem Stegreif' improvisieren musste — sein Solo ist kurz, weil er die Coltrane Changes noch nicht vollständig beherrschte." },
{ q: "Die Tritonussubstitution ist eine Technik, die hauptsächlich entwickelt wurde im...", opts: ["Barockzeitalter", "Bebop und modernen Jazz (1940er–1950er Jahre)", "Renaissancezeitalter", "Dixieland-Jazz (1920er Jahre)"], a: 1, fb: "Die Tritonussubstitution entstand im Bebop (Charlie Parker, Dizzy Gillespie, Thelonious Monk, 1940er Jahre). Sie wurde in den 1950er Jahren theoretisiert und systematisiert, bevor Coltrane sie in den 1960er Jahren auf die Spitze trieb." },
{ q: "Auf Db7 (Substitution von G7 → C), was ist die große None?", opts: ["C", "Eb", "F", "Bb"], a: 1, fb: "None von Db = große Sekunde in der Oktave = Eb. Db9 = Db–F–Ab–Cb–Eb. Die None (Eb) ist auf Db7 verfügbar — sie löst sich durch Halbtonschritt aufwärts nach E in CMaj7 auf. Ausgezeichnete Stimmführung!" },
{ q: "Auf Db7 → C ist die Tredezime von Db7...", opts: ["Bb", "Eb", "B", "Ab"], a: 0, fb: "Tredezime von Db = große Sexte = Bb. Db13 enthält Bb als Tredezime. Bb → A (Quinte von C) = Halbton abwärts — schöne Auflösung. Die Tredezime (Bb) ist auf Db7 verfügbar, da sie einen Ganzton von Ab (Quinte von Db7) entfernt ist." },
{ q: "Die #11 von Db7 ist...", opts: ["G", "G (G naturel)", "F#", "Eb"], a: 1, fb: "#11 von Db = übermäßige Quarte = G (G naturel). Db7#11 enthält G als #11. G ist der Grundton von G7 — das ist eine schöne harmonische Verbindung zwischen den beiden substituierten Akkorden. Db7#11 → CMaj7 ist im Jazz sehr gebräuchlich." },
{ q: "Db7#11 → CMaj7: die #11 (G) löst sich auf nach...", opts: ["G (bleibt in CMaj7 liegen)", "F (Quinte von CMaj7)", "E (Terz von CMaj7)", "D (None von CMaj9)"], a: 0, fb: "G ist sowohl die #11 von Db7 als auch die Quinte von CMaj7. Die Note bleibt bei der Auflösung liegen — sie ist ein 'Common Tone' (gemeinsamer Ton), der eine bemerkenswerte Kontinuität zwischen dem Sub und der Auflösung gewährleistet. Gebräuchliche Technik in Jazz-Arrangements." },
{ q: "Die Tritonussubstitution bewahrt welche harmonische Funktion?", opts: ["Tonika", "Subdominante", "Dominante (Spannung → Auflösung)", "Modal"], a: 2, fb: "Db7 bleibt ein Dominantakkord — er erzeugt Spannung (durch seinen internen Tritonus B–F = Cb–F), die sich nach C auflöst. Die Dominantfunktion bleibt erhalten, auch wenn sich der Bass ändert. Das macht die Substitution harmonisch kohärent." },
{ q: "Die Stufe von Db7 in der C-Dur-Tonleiter ist...", opts: ["♭II7 (erniedrigte zweite Stufe)", "IV7", "VI7", "♭VII7"], a: 0, fb: "Db ist die erniedrigte zweite Stufe von C-Dur (♭II). Db7 als Tritonussubstitution von G7 wird in der Funktionsanalyse daher als ♭II7 bezeichnet. Diese Bewegung ♭II7→I wird in manchen Analysen 'neapolitanische Auflösung' genannt — obwohl der Jazz-Mechanismus sich vom klassischen neapolitanischen Akkord unterscheidet." },
{ q: "Die Tritonussubstitution der Sekundärdominante V7/II (A7) in C ist...", opts: ["D7", "Eb7", "E♭7", "Eb7 (= Eb7)"], a: 3, fb: "A7 (Dominante von Dm) + 6 Halbtöne = Eb7. Die Tritonussubstitution von A7 ist Eb7. In einer Progression Dm7–A7–G7 kann man substituieren: Dm7–Eb7–G7 oder Dm7–Eb7–Db7, wodurch ein chromatischer Abstieg Eb→Db→C entsteht." },
{ q: "Die Auflösung Db7 → CMaj7 wird manchmal mit der neapolitanischen Kadenz verglichen, weil...", opts: ["beide einen Akkord auf ♭II verwenden", "beide vollkommene Kadenzen sind", "beide aus dem Barock stammen", "beide den Tritonus verwenden"], a: 0, fb: "Der neapolitanische Akkord (klassisches ♭II6) und die Tritonussubstitution Db7 teilen die Verwendung eines Akkords mit dem Grundton ♭II (Db in C). Die Mechanismen unterscheiden sich (klassische Stimmführung vs. Jazz-Tritonus), aber die Funktion ♭II→I ist beiden gemeinsam." },
{ q: "Die Tritonussubstitution verbessert die Stimmführung, weil...", opts: ["sie alle Dissonanzen beseitigt", "sie Halbtonbewegungen (chromatische Stimmführung) statt Quintensprünge erzeugt", "sie die Harmonik vereinfacht", "sie den Tritonus vermeidet"], a: 1, fb: "Quintensprünge (G→C) erzeugen eine starke Progression mit großen Intervallen. Die Tritonussubstitution (Db→C) ersetzt den Quintsprung durch einen Halbton, verbessert die Linearität und Flüssigkeit der Stimmen. Das ist das chromatische Voice Leading des Jazz." },
{ q: "Bei der Substitution Db7→CMaj7, wie viele Stimmen bewegen sich um einen Halbton?", opts: ["1", "2", "3", "0"], a: 2, fb: "3 Stimmen bewegen sich um einen Halbton: Db→C (Bass, ½ Ton), F→E (Terz von Db7 → Terz von CMaj7, ½ Ton), B→C (♭7 von Db7 → Grundton von CMaj7, ½ Ton aufwärts). Nur Ab (Quinte von Db7) muss zu G (Quinte von CMaj7) springen. Außergewöhnliche Stimmführung!" },
{ q: "Bei der Auflösung G7→CMaj7 (Standard), wie viele Stimmen bewegen sich um einen Halbton?", opts: ["0", "1", "2", "3"], a: 2, fb: "G7→CMaj7: B→C (½ Ton, Leitton zur Tonika) und F→E (½ Ton, ♭7 zur Terz). G (Bass) springt zu C (Quinte). D kann zu G oder C springen. Zwei Halbtonbewegungen — weniger glatt als die Substitution (3 Halbtöne)." },
{ q: "Die 'Coltrane Changes' teilen die Oktave in...", opts: ["2 gleiche Teile (Tritoni)", "3 gleiche Teile (große Terzen)", "4 gleiche Teile (kleine Terzen)", "6 gleiche Teile (Ganztöne)"], a: 1, fb: "Die Coltrane Changes teilen die Oktave in 3 gleiche Teile durch große Terzen (je 4 Halbtöne): B → G → Eb → B (Rückkehr). Jede Terzteilung erzeugt ein temporäres Tonzentrum. Dieser Großterzzirkel wird auch 'Coltrane-Bewegung' oder 'Coltrane-Kadenz' genannt." },
{ q: "Welches Album von John Coltrane (1960) hat die Jazz-Harmonik revolutioniert?", opts: ["A Love Supreme", "Kind of Blue", "Giant Steps", "My Favorite Things"], a: 2, fb: "Giant Steps (1960) ist das Album, das die 'Coltrane Changes' einführte — eine harmonische Progression durch große Terzen in unerhörter Geschwindigkeit. Der Titeltrack 'Giant Steps' ist einer der schwierigsten Jazz-Standards für die Improvisation." },
{ q: "Coltranes Saxophon auf 'A Love Supreme' (1964) verwendet eher...", opts: ["schnelle Coltrane Changes", "einen moderen Modalstil über Vamps", "systematische Tritonussubstitutionen", "ausschließlich Pentatonikskalen"], a: 1, fb: "A Love Supreme (1964) ist modaler — inspiriert von Miles Davis' Kind of Blue. Coltrane verwendet hier lange Improvisationen über modale Vamps statt komplexer harmonischer Progressionen. Es ist ein Gleichgewicht zwischen seinem harmonischen Ansatz aus Giant Steps und dem modalen Jazz." },
{ q: "Im Hören klingt Db7→C verglichen mit G7→C...", opts: ["abrupter und stärker", "glatter und chromatischer — Gefühl des 'Gleitens'", "identisch", "dissonanter"], a: 1, fb: "Db7→C klingt glatter, weil der Bass sich um einen Halbton bewegt (Db→C). Die Auflösung wirkt, als würde sie zur Tonika 'gleiten', statt dort 'hineinzufallen' (wie bei G→C durch Quinte). Das Ergebnis ist überraschender und raffinierter — Merkmal des modernen Jazz." },
{ q: "Der Bass Db→C in Db7→C erzeugt ein Intervall von...", opts: ["großer Sekunde (Ganzton)", "kleiner Sekunde (Halbton)", "kleiner Terz", "Quinte"], a: 1, fb: "Db→C = kleine Sekunde = Halbton = 1 Halbton. Das ist das kleinste Intervall der westlichen temperierten Stimmung. Die Auflösung durch absteigenden Halbton ist die glattestmögliche — daher der Effekt des 'chromatischen Gleitens', der im Jazz so begehrt ist." },
{ q: "Der Bass G→C in G7→C erzeugt ein Intervall von...", opts: ["reine Quarte (aufwärts)", "reine Quinte (abwärts)", "große Terz", "Sexte"], a: 1, fb: "G→C abwärts = reine Quinte (7 Halbtöne). G→C aufwärts = reine Quarte. In der Bassbewegung spricht man vom 'Quintfall' (G abwärts nach C). Das ist die stärkste Kadenzbewegung der Tonalität." },
{ q: "Können G7 und Db7 zusammen im selben Takt verwendet werden?", opts: ["Nein — sie schließen sich gegenseitig aus", "Ja — oft als chromatische Durchgangsakkorde (G7–Db7–C)", "Ja, aber nur in Moll", "Nein — sie klingen gleich, weil sie denselben Tritonus haben"], a: 1, fb: "G7 und Db7 können als chromatische Durchgangsakkorde koexistieren: G7–Db7–CMaj7 in einer einzigen Progression. Der Bass steigt G→Db→C ab (Tritonus, dann Halbton). In manchen Arrangements findet man auch G7–Gb7–C (♭V7 als Durchgangsakkord)." },
{ q: "Ist der 'Backdoor Dominant' (♭VII7→I, z.B. Bb7→C) mit der Tritonussubstitution verwandt?", opts: ["Nein — völlig anderer Mechanismus", "Ja — Bb7 ist der Tritonus-Sub von E7, nicht von G7 (verwandte, aber unterschiedliche Mechanismen)", "Ja — es ist exakt dasselbe", "Nein — der Backdoor verwendet keinen Tritonus"], a: 1, fb: "Der Backdoor Dominant (Bb7→C = ♭VII7→I) verwendet einen Akkord im Abstand einer großen Sekunde von der Tonika, keinen Tritonus. Es ist ein verwandter harmonischer Mechanismus (Auflösung durch Gleiten), aber verschieden von der Tritonussubstitution. Beide teilen jedoch die Idee, sich von einem unkonventionellen Akkord nach I aufzulösen." },
{ q: "In einem Blues in A wird die Kadenz IV7–I7 (D7–A7) mit Substitution zu...", opts: ["D7–Eb7", "Ab7–A7", "Ab7–Eb7", "D7–Ab7"], a: 3, fb: "D7 (IV7 in A) wird in diesem Kontext normalerweise nicht substituiert. Aber A7 (I7 im Blues) → A + 6 Halbtonschritte = Eb. Substitution von A7 = Eb7. Im Blues wird die Tritonussubstitution vor allem auf V7 angewendet (E7→A): E7 → Bb7. Bb7→A erzeugt eine chromatische Auflösung um ½ Ton." },
  { q: "Kann die Tritonussubstitution auf den IVMaj7 (Subdominante) angewendet werden?", opts: ["Ja — FMaj7 kann durch BMaj7 ersetzt werden", "Nein — der IVMaj7 hat keinen instabilen Tritonus zur Auflösung", "Ja, aber nur im Jazzfusion", "Nein — der IVMaj7 ist immer stabil"], a: 1, fb: "Nein. Die Tritonussubstitution gilt nur für Dominantseptakkorde (mit instabilem Tritonus). Ein IVMaj7-Akkord (FMaj7) hat eine große Septime — sein interner Tritonus ist anders und hat nicht dieselbe Auflösungsdringlichkeit." },
  { q: "Charlie Parker verwendete in seinen Improvisationen oft...", opts: ["nur Pentatonikskalen", "Substitutionen und Turnarounds mit Triton-Subs für chromatische Linien", "nur die Durtonleiter", "gestapelte Quartenakkorde"], a: 1, fb: "Charlie Parker ('Bird') war ein Meister der harmonischen Substitutionen — er improvisierte in Echtzeit über G7–Db7–C und schuf sehr chromatische Bebop-Linien. Er sagte: 'Wenn du nicht in der Harmonie lebst, wirst du immer außerhalb sein.' Triton-Subs sind das Herzstück des Bebops." },
  { q: "Miles Davis in 'Round Midnight' (Arrangement) verwendet Substitutionen um...", opts: ["Monks Originalakkorde zu vereinfachen", "Monks Harmonien mit chromatischen Substitutionen zu bereichern", "verminderte Akkorde zu vermeiden", "das Stück in eine andere Tonart zu transponieren"], a: 1, fb: "Miles Davis und Gil Evans bereicherten 'Round Midnight' (ursprünglich von Monk) mit zahlreichen Substitutionen, insbesondere Triton-Subs, und schufen eine dichtere harmonische Textur. Ein perfektes Beispiel für Jazz-Reharmonisierung." },
  { q: "Die Beziehung zwischen G7 und Db7 kann auch gesehen werden als...", opts: ["eine entfernte Modulation", "zwei Akkorde im Tritonusabstand, deren Leittonrollen sich umkehren", "zwei Akkorde mit demselben Grundton", "zwei Akkorde mit derselben Quinte"], a: 1, fb: "G7 und Db7 stehen im Tritonusabstand (6 Halbtöne) zueinander. Ihre Leittöne (H/Ces und F) sind exakt dieselben, mit vertauschten Rollen (Terz ↔ Septime). Das ist eine elegante harmonische Symmetrie im Herzen der Tritonussubstitution." },
];

const questionsIt: Question[] = [{ q: "Un tritono è un intervallo di...", opts: ["5 semitoni", "6 semitoni", "7 semitoni", "4 semitoni"], a: 1, fb: "Il tritono = 6 semitoni = quarta aumentata = quinta diminuita. È l'intervallo più dissonante della scala temperata — divide l'ottava (12 semitoni) esattamente in due. Es: Do → Fa# = 6 semitoni." },
{ q: "Perché il tritono è chiamato 'diabolus in musica' nel Medioevo?", opts: ["Era facile da suonare", "Era l'intervallo più consonante", "La sua estrema dissonanza era considerata pericolosa ed era proibita", "Assomigliava al suono di un diavolo"], a: 2, fb: "Nel Medioevo e nel Rinascimento, il tritono era esplicitamente proibito nella musica sacra a causa della sua dissonanza. 'Diabolus in musica' (diavolo nella musica) è un'espressione che risale al trattato di Johannes de Muris (XIV secolo)." },
{ q: "Il tritono di Sol è...", opts: ["Ré", "Do#", "Réb", "La"], a: 2, fb: "Sol → Réb = 6 semitoni. Sol + 6 = Réb. Ecco perché Db7 è la sostituzione tritonica di G7." },
{ q: "Il tritono di Do è...", opts: ["Sol", "Fa#", "Sib", "La#"], a: 1, fb: "Do → Fa# = 6 semitoni. Do=0, +6=Fa#(Gb). La sostituzione tritonica di C7 è F#7 (o Gb7 a seconda del contesto)." },
{ q: "Il tritono di Ré è...", opts: ["Sol#", "Lab", "Sol#/Lab (enarmoniche)", "Sol"], a: 2, fb: "Ré + 6 semitoni = Sol# = Lab (note enarmoniche). Le due notazioni sono equivalenti. La sostituzione tritonica di D7 è Ab7." },
{ q: "Quante coppie di sostituzioni tritoniche esistono nelle 12 tonalità?", opts: ["6 coppie", "12 coppie", "24 coppie", "3 coppie"], a: 0, fb: "Esistono 6 coppie di sostituzioni tritoniche: G7↔Db7, D7↔Ab7, A7↔Eb7, E7↔Bb7, B7↔F7, F#7↔C7. Ogni coppia condivide lo stesso tritono interno (i guide tones)." },
{ q: "G7 contiene il tritono B – F. In Db7, queste stesse note sono...", opts: ["La 9a e la 5a", "La ♭7a (Cb=B) e la 3a (F)", "La 3a e la quinta", "La fondamentale e la 9a"], a: 1, fb: "In Db7: la 3a è Fa (F) e la ♭7a è Do♭ (Cb = B naturale enarmonicamente). Il tritono F–B è condiviso tra G7 e Db7, ma i ruoli si invertono: B (3a di G7) diventa ♭7 di Db7; F (♭7 di G7) diventa 3a di Db7." },
{ q: "I 'guide tones' di un accordo sono...", opts: ["la fondamentale e la 5a", "la 3a e la 7a", "la 9a e la 13a", "la fondamentale e la 9a"], a: 1, fb: "I guide tones = 3a + 7a. Sono le note che definiscono la qualità (maggiore/minore) e la tensione (dominante/Maj7) di un accordo. La fondamentale e la 5a sono acusticamente ridondanti; 3a e 7a portano tutta l'informazione armonica." },
{ q: "Nella sostituzione tritonica, i guide tones...", opts: ["scompaiono completamente", "rimangono identici ma scambiano i loro ruoli (3a ↔ 7a)", "si spostano di un semitono", "raddoppiano di ottava"], a: 1, fb: "Questo è il segreto della sostituzione tritonica: le due note del tritono rimangono presenti, ma i loro ruoli si invertono. La 3a di G7 (Si/B) diventa la ♭7a di Db7 (Do♭/Cb). La ♭7a di G7 (Fa/F) diventa la 3a di Db7 (Fa/F). Entrambi gli accordi risolvono verso C per la stessa ragione: condividono lo stesso tritono instabile." },
{ q: "Perché G7 e Db7 risolvono entrambi verso Do maggiore?", opts: ["Per sola convenzione storica", "Perché condividono lo stesso tritono interno (B–F = Cb–F) che risolve verso C", "Perché hanno la stessa fondamentale", "Perché hanno la stessa 5a"], a: 1, fb: "G7 e Db7 condividono le note B (=Cb) e F — il tritono. Questo tritono risolve verso C e E (B→C semitono ascendente, F→E semitono discendente). Indipendentemente dal fatto che il basso sia G o Db, i guide tones risolvono identicamente verso CMaj7." },
{ q: "La risoluzione del tritono B–F verso C–E implica...", opts: ["B sale di un semitono verso C; F scende di un semitono verso E", "B scende verso A; F sale verso G", "B e F rimangono fermi", "B sale di un tono verso C#; F scende di un tono verso Eb"], a: 0, fb: "B → C (semitono ascendente) e F → E (semitono discendente). Questi due movimenti di semitono convergono verso la tonica C e la sua 3a E. È questa attrazione del tritono verso la terza maggiore della tonica che genera la tensione → risoluzione." },
{ q: "La cadenza standard G7 → C implica quale movimento del basso?", opts: ["Cromatico discendente (G→Gb→F→E→...→C)", "Discesa di quinta (G down to C = discesa di quinta giusta)", "Salita di quarta", "Rimane su G"], a: 1, fb: "G7 → C: il basso scende di una quinta giusta (7 semitoni) da Sol a Do. Questo movimento di quinta discendente (o salita di quarta) è il movimento cadenziale più forte della tonalità — la ragione per cui V→I è la risoluzione archetipica." },
{ q: "La cadenza tritonica Db7 → C implica quale movimento del basso?", opts: ["Discesa di quinta (Db → Gb)", "Salita di un semitono (Db→D)", "Discesa di un semitono cromatico (Db→C)", "Rimane su Db"], a: 2, fb: "Db7 → C: il basso scende di un semitono da Réb a Do. È il movimento cromatico più fluido possibile. Questa risoluzione per scivolamento (piuttosto che per salto di quinta) è il principale vantaggio della sostituzione tritonica: morbidezza e cromatismo." },
{ q: "Nel II-V-I standard (Dm7–G7–CMaj7), la linea del basso è...", opts: ["D → Db → C (cromatica)", "D → G → C (quinte discendenti)", "D → E → C", "D → A → C"], a: 1, fb: "Dm7–G7–CMaj7 in Do: basso = Ré–Sol–Do. Ré→Sol = quinta discendente (o quarta ascendente); Sol→Do = quinta discendente. Progressione per ciclo delle quinte — armonicamente molto forte, meno fluida linearmente." },
{ q: "Nel II-V-I con sostituzione (Dm7–Db7–CMaj7), la linea del basso è...", opts: ["D → G → C", "D → Db → C (discesa cromatica!)", "D → E → C", "D → Ab → C"], a: 1, fb: "Con la sostituzione tritonica: basso = Ré–Réb–Do. È una discesa cromatica di 3 note (D→Db→C). Questa linea di basso è uno degli effetti più caratteristici del jazz moderno — il pianista o il bassista può creare questa voce interna che scende per semitoni." },
{ q: "Qual è il principale vantaggio della linea di basso D–Db–C rispetto a D–G–C?", opts: ["È armonicamente più forte", "È più cromatica e fluida — migliore conduzione delle voci", "Evita ogni dissonanza", "È più facile da cantare"], a: 1, fb: "D–Db–C è una discesa cromatica di 3 note consecutive (ogni nota è un semitono più bassa). Questa continuità lineare crea una sensazione di 'scivolamento' molto apprezzata in jazz. D–G–C è armonicamente più forte ma meno fluida melodicamente." },
{ q: "Qual è la sostituzione tritonica di D7?", opts: ["G7", "Ab7", "Eb7", "A7"], a: 1, fb: "Ré + 6 semitoni = Lab = Ab. La sostituzione tritonica di D7 è Ab7. Verifica: D7 contiene F#–C (tritono). Ab7 contiene C–Gb/F# (stesso tritono). ✓" },
{ q: "Qual è la sostituzione tritonica di A7?", opts: ["Eb7", "D7", "Bb7", "E7"], a: 0, fb: "La + 6 semitoni = Mi♭ = Eb. La sostituzione tritonica di A7 è Eb7. A7 contiene C#–G (tritono). Eb7 contiene G–Db (= C#). Stesso tritono, ruoli invertiti. ✓" },
{ q: "Qual è la sostituzione tritonica di E7?", opts: ["B7", "Bb7", "A7", "F7"], a: 1, fb: "Mi + 6 semitoni = Si♭ = Bb. La sostituzione tritonica di E7 è Bb7. E7 contiene G#–D (tritono). Bb7 contiene D–Ab (= G#). ✓" },
{ q: "Qual è la sostituzione tritonica di C7?", opts: ["F7", "G7", "F#7/Gb7", "Gb7 soltanto"], a: 2, fb: "Do + 6 semitoni = Fa# = Gb. La sostituzione tritonica di C7 è F#7 (o Gb7). C7 contiene E–Bb (tritono). Gb7 contiene Bb–E. Stesso tritono invertito. ✓" },
{ q: "Qual è la sostituzione tritonica di F7?", opts: ["C7", "B7", "Gb7", "Bb7"], a: 1, fb: "Fa + 6 semitoni = Si = B. La sostituzione tritonica di F7 è B7. F7 contiene A–Eb (tritono). B7 contiene D#–A (= Eb–A). ✓" },
{ q: "Qual è la sostituzione tritonica di Bb7?", opts: ["Eb7", "F7", "E7", "Ab7"], a: 2, fb: "Si♭ + 6 semitoni = Mi = E. La sostituzione tritonica di Bb7 è E7. Bb7 contiene D–Ab (tritono). E7 contiene G#–D (= Ab–D). ✓" },
{ q: "Se il tritono sub di G7 è Db7, qual è il tritono sub di Db7?", opts: ["G♭7", "G7", "Ab7", "C7"], a: 1, fb: "La relazione è reciproca: se Db7 è il tritono sub di G7, allora G7 è il tritono sub di Db7. Réb + 6 = Sol. Ogni coppia di sostituzioni tritoniche è simmetrica — si può sostituire in entrambe le direzioni." },
{ q: "In Autumn Leaves, la cadenza Am7♭5–D7–Gm con sostituzione diventa...", opts: ["Am7♭5–Ab7–Gm", "Am7♭5–G7–Gm", "Bm7♭5–Ab7–Gm", "Am7♭5–Db7–Gm"], a: 0, fb: "D7 → sub tritonica = Ab7 (Ré + 6 = Lab). Autumn Leaves: Am7♭5–D7–Gm con sub → Am7♭5–Ab7–Gm. La linea di basso A–Ab–G scende cromaticamente — molto comune negli arrangiamenti jazz di questo standard." },
{ q: "La sostituzione tritonica può essere applicata a...", opts: ["soltanto il V7 principale", "qualsiasi accordo di dominante 7a (incluse le dominanti secondarie)", "soltanto gli accordi maggiori", "soltanto nel jazz bebop"], a: 1, fb: "Qualsiasi accordo dominante 7a (contenente un tritono interno) può essere sostituito. Ciò include le dominanti secondarie: V7/II (A7→Eb7), V7/IV (C7→Gb7), ecc. È per questa ragione che la sostituzione tritonica è così versatile." },
{ q: "In un ciclo II–V–I–IV–VII–III–VI, si possono sostituire tutti i V7?", opts: ["No — soltanto il V7 principale", "Sì — ogni dominante 7a può essere sostituito dal suo tritono sub", "Sì, ma soltanto i V7 dispari", "No — ciò romperebbe la tonalità"], a: 1, fb: "Sì. In un ciclo di dominanti (es: G7–C7–F7–Bb7 ecc.), ogni accordo può essere sostituito dal suo tritone sub: Db7–Gb7–B7–E7 ecc. Questa 'catena di sostituzioni' crea una discesa cromatica continua nel basso — texture molto jazz moderno." },
{ q: "La 'sostituzione di Coltrane' in Giant Steps utilizza...", opts: ["lo stesso tritono condiviso", "un ciclo di terze maggiori (divide l'ottava in 3 parti uguali)", "soltanto dominanti secondarie", "accordi diminuiti"], a: 1, fb: "I 'Coltrane changes' di Giant Steps (1960) estendono il concetto di sostituzione con un ciclo di terze maggiori: B → G → E♭ (ciascuno a distanza di terza maggiore = 4 semitoni). Non è direttamente la sostituzione tritonica, ma uno sviluppo armonico affine — dividere l'ottava in 3 parti uguali." },
{ q: "In Giant Steps, Coltrane passa per quanti centri tonali diversi in 2 misure?", opts: ["1", "2", "3", "4"], a: 2, fb: "Giant Steps progredisce attraverso 3 centri tonali (B, G, E♭) in 2 misure — un movimento armonico a una velocità inaudita per il 1959. Ogni centro dura circa 2 tempi. È quello che i musicisti dell'epoca chiamavano 'correre i cambiamenti' — bisognava improvvisare a una velocità armonica estrema." },
{ q: "Quale pianista ha registrato Giant Steps con Coltrane nel 1960?", opts: ["Bill Evans", "Herbie Hancock", "Tommy Flanagan", "McCoy Tyner"], a: 2, fb: "Tommy Flanagan ha suonato il pianoforte su Giant Steps (1960). La storia racconta che era talmente sorpreso dall'armonia di Coltrane durante la registrazione che dovette improvvisare 'a memoria' — il suo assolo è breve perché non padroneggiava ancora i Coltrane changes." },
{ q: "La sostituzione tritonica è una tecnica sviluppata principalmente nel...", opts: ["musica barocca", "bebop e jazz moderno (anni 1940-1950)", "musica rinascimentale", "jazz dixieland (anni 1920)"], a: 1, fb: "La sostituzione tritonica è nata nel bebop (Charlie Parker, Dizzy Gillespie, Thelonious Monk, anni 1940). È stata teorizzata e sistematizzata negli anni 1950 prima di essere portata all'estremo da Coltrane negli anni 1960." },
{ q: "Su Db7 (sostituzione di G7 → C), qual è la 9a maggiore?", opts: ["Do", "Mi♭", "Fa", "Si♭"], a: 1, fb: "9a di Réb = 2a maggiore all'ottava = Mi♭. Db9 = Réb–Fa–Lab–Do♭–Mi♭. La 9a (Mi♭) è disponibile su Db7 — risolve verso Mi naturale in CMaj7 per semitono ascendente. Ottimo movimento di voce!" },
{ q: "Su Db7 → C, la 13a di Db7 è...", opts: ["Si♭", "Mi♭", "Si", "La♭"], a: 0, fb: "13a di Réb = 6a maggiore = Si♭. Db13 contiene Si♭ come 13a. Si♭ → La (5a di C) = semitono discendente — bella risoluzione. La 13a (Bb/Si♭) è disponibile su Db7 poiché si trova a distanza di tono da Lab (5a di Db7)." },
{ q: "La #11 di Db7 è...", opts: ["Sol", "Sol naturale (G)", "Fa#", "Mi♭"], a: 1, fb: "#11 di Réb = 4a aumentata = Sol naturale (G). Db7#11 contiene Sol come #11. Sol è la fondamentale di G7 — è una bella connessione armonica tra i due accordi sostituiti. Db7#11 → CMaj7 è molto comune in jazz." },
{ q: "Db7#11 → CMaj7: la #11 (Sol) risolve verso...", opts: ["Sol (rimane in CMaj7)", "Fa (5a di CMaj7)", "Mi (3a di CMaj7)", "Ré (9a di CMaj9)"], a: 0, fb: "Sol è allo stesso tempo la #11 di Db7 e la quinta di CMaj7. La nota rimane ferma durante la risoluzione — è una 'common tone' (nota comune) che assicura una notevole continuità tra il sub e la risoluzione. Tecnica comune negli arrangiamenti jazz." },
{ q: "La sostituzione tritonica preserva quale funzione armonica?", opts: ["Tonica", "Sottodominante", "Dominante (tensione → risoluzione)", "Modale"], a: 2, fb: "Db7 rimane un accordo di dominante — crea tensione (tramite il suo tritono interno B–F = Cb–F) che risolve verso C. La funzione dominante è preservata anche se il basso cambia. È ciò che rende la sostituzione armonicamente coerente." },
{ q: "Il grado di Db7 nella scala di Do maggiore è...", opts: ["♭II7 (secondo grado bemolle)", "IV7", "VI7", "♭VII7"], a: 0, fb: "Réb è il II grado bemolle di Do maggiore (♭II). Db7 usato come sostituzione tritonica di G7 è quindi annotato ♭II7 nell'analisi funzionale. Questo movimento ♭II7→I è chiamato 'risoluzione napoletana' in alcune analisi — sebbene il meccanismo jazz sia diverso dall'accordo napoletano classico." },
{ q: "La sostituzione tritonica della dominante secondaria V7/II (A7) in Do è...", opts: ["D7", "Eb7", "E♭7", "Eb7 (= Mi♭7)"], a: 3, fb: "A7 (dominante di Dm) + 6 semitoni = Eb7. La sostituzione tritonica di A7 è Eb7. In una progressione Dm7–A7–G7, si può sostituire: Dm7–Eb7–G7 o Dm7–Eb7–Db7, creando una discesa cromatica Mi♭→Ré♭→Do." },
{ q: "La risoluzione Db7 → CMaj7 viene talvolta paragonata alla cadenza napoletana perché...", opts: ["entrambe usano un accordo su ♭II", "entrambe sono cadenze perfette", "entrambe provengono dal barocco", "entrambe usano il tritono"], a: 0, fb: "L'accordo napoletano (♭II6 classico) e la sostituzione tritonica Db7 condividono il fatto di utilizzare un accordo la cui fondamentale è ♭II (Réb in Do). I meccanismi differiscono (conduzione di voce classica vs tritono jazz), ma la funzione ♭II→I è comune." },
{ q: "La sostituzione tritonica migliora la conduzione delle voci perché...", opts: ["elimina tutte le dissonanze", "crea movimenti per semitoni (conduzione cromatica delle voci) invece di salti di quinta", "semplifica l'armonia", "evita il tritono"], a: 1, fb: "I salti di quinta (G→C) creano una progressione forte ma con grandi intervalli. La sostituzione tritonica (Db→C) sostituisce il salto di quinta con un semitono, migliorando la linearità e la fluidità delle voci. È il chromatic voice leading del jazz." },
{ q: "Nella sostituzione Db7→CMaj7, quante voci si muovono per semitono?", opts: ["1", "2", "3", "0"], a: 2, fb: "3 voci si muovono per semitono: Réb→Do (basso, ½ tono), Fa→Mi (3a di Db7 → 3a di CMaj7, ½ tono), Si→Do (♭7a di Db7 → fondamentale di CMaj7, ½ tono ascendente). Solo Lab (5a di Db7) deve saltare verso Sol (quinta di CMaj7). Conduzione di voce eccezionale!" },
{ q: "Nella risoluzione G7→CMaj7 (standard), quante voci si muovono per semitono?", opts: ["0", "1", "2", "3"], a: 2, fb: "G7→CMaj7: Si→Do (½ tono, sensibile verso tonica) e Fa→Mi (½ tono, ♭7a verso 3a). Sol (basso) salta a Do (quinta). Ré può saltare verso Sol o Do. Due movimenti per semitono — meno fluido della sostituzione (3 semitoni)." },
{ q: "I 'Coltrane changes' dividono l'ottava in...", opts: ["2 parti uguali (tritoni)", "3 parti uguali (terze maggiori)", "4 parti uguali (terze minori)", "6 parti uguali (toni interi)"], a: 1, fb: "I Coltrane changes dividono l'ottava in 3 parti uguali per terze maggiori (4 semitoni ciascuna): B → G → E♭ → B (ritorno). Ogni divisione di terza maggiore genera un centro tonale temporaneo. Questo ciclo per terze maggiori è anche chiamato 'movimento di Coltrane' o 'cadenza di Coltrane'." },
{ q: "Quale album di John Coltrane (1960) ha rivoluzionato l'armonia jazz?", opts: ["A Love Supreme", "Kind of Blue", "Giant Steps", "My Favorite Things"], a: 2, fb: "Giant Steps (1960) è l'album che ha introdotto i 'Coltrane changes' — una progressione armonica per terze maggiori a una velocità inaudita. Il brano principale 'Giant Steps' è diventato uno degli standard jazz più difficili su cui improvvisare." },
{ q: "Il sassofono di Coltrane su 'A Love Supreme' (1964) usa piuttosto...", opts: ["Coltrane changes rapidi", "uno stile modale più statico su vamp", "la sostituzione tritonica sistematica", "soltanto scale pentatoniche"], a: 1, fb: "A Love Supreme (1964) è più modale — ispirato da Kind of Blue di Miles Davis. Coltrane usa qui lunghe improvvisazioni su vamp modali piuttosto che progressioni armoniche complesse. È un equilibrio tra il suo approccio armonico di Giant Steps e il jazz modale." },
{ q: "All'orecchio, Db7→C suona rispetto a G7→C...", opts: ["Più brusco e forte", "Più fluido e cromatico — sensazione di 'scivolamento'", "Identico", "Più dissonante"], a: 1, fb: "Db7→C suona più fluido perché il basso scende per semitono (Réb→Do). La risoluzione sembra 'scivolare' verso la tonica piuttosto che 'caderci' (come in G→C per quinta). Il risultato è più sorprendente e sofisticato — firma del jazz moderno." },
{ q: "Il basso Réb→Do in Db7→C crea un intervallo di...", opts: ["seconda maggiore (tono)", "seconda minore (semitono)", "terza minore", "quinta"], a: 1, fb: "Réb→Do = seconda minore = semitono = 1 semitono. È il più piccolo intervallo della scala temperata occidentale. La risoluzione per semitono discendente è la più fluida possibile — da qui l'effetto di 'scivolamento cromatico' molto ricercato in jazz." },
{ q: "Il basso Sol→Do in G7→C crea un intervallo di...", opts: ["quarta giusta (ascendente)", "quinta giusta (discendente)", "terza maggiore", "sesta"], a: 1, fb: "Sol→Do discendente = quinta giusta (7 semitoni). Sol→Do ascendente = quarta giusta. In termini di movimento del basso, si dice 'discesa di quinta' (G down to C). È il movimento cadenziale più forte della tonalità." },
{ q: "Si possono sentire G7 e Db7 usati insieme nella stessa misura?", opts: ["No — si escludono a vicenda", "Sì — spesso come accordi di passaggio cromatici (G7–Db7–C)", "Sì, ma soltanto in modo minore", "No — hanno lo stesso tritono quindi suonano uguali"], a: 1, fb: "G7 e Db7 possono coesistere come accordi di passaggio cromatici: G7–Db7–CMaj7 in un'unica progressione. Il basso scende G→Db→C per tritono poi semitono. Si vede anche G7–G♭7–C (♭V7 come passing chord) in certi arrangiamenti." },
{ q: "Il 'backdoor dominant' (♭VII7→I, es: Bb7→C) è legato alla sostituzione tritonica?", opts: ["No — meccanismo completamente diverso", "Sì — Bb7 è il tritono sub di E7, non di G7 (meccanismi affini ma distinti)", "Sì — è esattamente la stessa cosa", "No — il backdoor non usa il tritono"], a: 1, fb: "Il backdoor dominant (Bb7→C = ♭VII7→I) usa un accordo a distanza di tono dalla tonica, non di tritono. È un meccanismo armonico affine (risoluzione per scivolamento) ma distinto dalla sostituzione tritonica. Condividono tuttavia l'idea di risolvere verso I da un accordo non convenzionale." },
{ q: "In un blues in La, la cadenza IV7–I7 (D7–A7) con sostituzione diventa...", opts: ["D7–Eb7", "Ab7–A7", "Ab7–Eb7", "D7–Ab7"], a: 3, fb: "D7 (IV7 in La) non viene solitamente sostituito in questo contesto. Ma A7 (I7 nel blues) → La + 6 = Mi♭. Sostituzione di A7 = Eb7. Nel blues, la sostituzione tritonica si applica soprattutto ai V7 (E7→La): E7 → Bb7. Bb7→A crea una risoluzione cromatica per ½ tono." },
{ q: "La sostituzione tritonica può essere applicata al IVMaj7 (sottodominante maggiore)?", opts: ["Sì — FMaj7 può essere sostituito da BMaj7", "No — il IVMaj7 non ha un tritono instabile da risolvere", "Sì, ma soltanto in jazz fusion", "No — il IVMaj7 è sempre stabile"], a: 1, fb: "No. La sostituzione tritonica si applica soltanto agli accordi di dominante 7a (contenenti un tritono instabile). Un accordo IVMaj7 (FMaj7) ha una 7a maggiore — il suo tritono interno è diverso e non ha la stessa urgenza di risoluzione. Il concetto di sub è legato alla tensione dominante." },
{ q: "Charlie Parker usava spesso nelle sue improvvisazioni...", opts: ["soltanto scale pentatoniche", "'sostituzioni' e 'turnarounds' con i tritono sub per creare linee cromatiche", "soltanto la scala maggiore", "accordi di quarte sovrapposte"], a: 1, fb: "Charlie Parker ('Bird') era un maestro delle sostituzioni armoniche — improvvisava su G7–Db7–C in tempo reale, creando linee bebop molto cromatiche. Ha detto: 'Se non vivi nell'armonia, sarai sempre fuori.' I tritono sub sono al cuore del bebop." },
{ q: "Miles Davis in 'Round Midnight' (arrangiamento) usa delle sostituzioni per...", opts: ["semplificare gli accordi originali di Monk", "arricchire i cambiamenti di Monk con sostituzioni cromatiche", "evitare gli accordi diminuiti", "trasporre il brano in un'altra tonalità"], a: 1, fb: "Miles Davis e Gil Evans hanno arricchito 'Round Midnight' (originariamente di Monk) con numerose sostituzioni, soprattutto tritono subs, creando una texture armonica più densa. È un esempio perfetto di riarmonizzazione jazz." },
  { q: "La relazione tra G7 e Db7 può anche essere vista come...", opts: ["una modulazione distante", "due accordi a distanza di tritono i cui ruoli di guide tones si invertono", "due accordi con la stessa fondamentale", "due accordi con la stessa 5ª"], a: 1, fb: "G7 e Db7 sono a distanza di tritono (6 semitoni) l'uno dall'altro. I loro guide tones (Si/Do♭ e Fa) sono esattamente gli stessi, con i ruoli invertiti (3ª ↔ 7ª). È una simmetria armonica elegante al cuore del tritono sub." },
];

